div.script:
//
window.addEventListener('DOMContentLoaded', function() {
    var header = document.getElementById('top');
    if (header) header.style.display = 'none';

    var badge = document.getElementById('kualeUserBadge');
    if (badge) {
        badge.addEventListener('click', function(e) {
            e.stopPropagation();
            this.classList.toggle('is-open');
        });
        document.addEventListener('click', function() {
            badge.classList.remove('is-open');
        });
    }

    var modal      = document.getElementById('kualeBranchModal');
    var modalTitle = document.getElementById('kualeBranchTitle');
    var modalMap   = document.getElementById('kualeBranchMap');
    var modalClose = document.getElementById('kualeBranchClose');

    document.querySelectorAll('.kuale-branch-link').forEach(function(link) {
        link.addEventListener('click', function(e) {
            e.preventDefault();
            var branch  = this.getAttribute('data-branch');
            var company = this.getAttribute('data-company');
            if (!branch || branch === 'N/A') {
                modalTitle.textContent = company + ' - Tamaulipas, México';
                var encodedQuery = encodeURIComponent(company + ' Tamaulipas México');
                modalMap.src = 'https://maps.google.com/maps?q=' + encodedQuery + '&output=embed&hl=es&z=9&iwloc=B';
            } else {
                modalTitle.textContent = company + ' - ' + branch;
                var encodedQuery = encodeURIComponent(company + ' ' + branch + ' Tamaulipas México');
                modalMap.src = 'https://maps.google.com/maps?q=' + encodedQuery + '&output=embed&hl=es&z=15&iwloc=B';
            }
            modal.classList.add('is-open');
            modal.style.overscrollBehavior = 'contain';
            modal._scrollY = window.scrollY;
            document.body.style.top = '-' + window.scrollY + 'px';
            document.body.style.position = 'fixed';
            document.body.style.width = '100%';
        });
    });

    if (modalClose) {
        modalClose.addEventListener('click', function() {
            modal.classList.remove('is-open');
            modalMap.src = '';
            document.body.style.position = '';
            document.body.style.top = '';
            document.body.style.width = '';
            window.scrollTo({ top: modal._scrollY || 0, behavior: 'instant' });
        });
    }

    if (modal) {
        modal.addEventListener('click', function(e) {
            if (e.target === modal) {
                modal.classList.remove('is-open');
                modalMap.src = '';
                document.body.style.position = '';
                document.body.style.top = '';
                document.body.style.width = '';
                window.scrollTo({ top: modal._scrollY || 0, behavior: 'instant' });
            }
        });
    }

    // ── Fix botón Aplicar en móvil (sin doble disparo) ──
    var loginHandled = false;

    document.querySelectorAll('[data-kuale-login="open"]').forEach(function(btn) {
        btn.addEventListener('click', function(e) {
            e.preventDefault();
            if (loginHandled) return;
            loginHandled = true;

            var redirect = this.getAttribute('data-redirect') || window.location.pathname;

            setTimeout(function() {
                loginHandled = false;
                var odooLoginModal = document.querySelector(
                    '.modal.show, .o_login_modal, [id*="Login"].is-open, [id*="login"].is-open'
                );
                if (!odooLoginModal) {
                    window.location.href = '/web/login?redirect=' + encodeURIComponent(redirect);
                }
            }, 500);
        });
    });

    // ── Modal Bolsa de trabajo info ──
    var bolsaInfoModal = document.getElementById('kualeBolsaInfoModal');
    var bolsaInfoClose = document.getElementById('kualeBolsaInfoClose');

    document.querySelectorAll('[data-kuale-bolsa-info="open"]').forEach(function(btn) {
        btn.addEventListener('click', function(e) {
            e.preventDefault();
            e.stopPropagation();
            if (bolsaInfoModal) {
                bolsaInfoModal.style.display = 'flex';
                bolsaInfoModal.style.overscrollBehavior = 'contain';
                document.body.classList.add('kuale-modal-open');
            }
        });
    });

    if (bolsaInfoClose) {
        bolsaInfoClose.addEventListener('click', function() {
            bolsaInfoModal.style.display = 'none';
            document.body.classList.remove('kuale-modal-open');
        });
    }

    if (bolsaInfoModal) {
        bolsaInfoModal.addEventListener('click', function(e) {
            if (e.target === bolsaInfoModal) {
                bolsaInfoModal.style.display = 'none';
                document.body.classList.remove('kuale-modal-open');
            }
        });
    }
});
//

(function() {
    function init() {
        // Dropdown usuario
        var badge = document.getElementById('kualeUserBadge');
        if (badge) {
            badge.addEventListener('click', function(e) {
                e.stopPropagation();
                this.classList.toggle('is-open');
            });
            document.addEventListener('click', function() {
                badge.classList.remove('is-open');
            });
        }

        // Modal mapa sucursal
        var modal = document.getElementById('kualeBranchModal');
        var modalTitle = document.getElementById('kualeBranchTitle');
        var modalMap = document.getElementById('kualeBranchMap');
        var modalClose = document.getElementById('kualeBranchClose');

        document.querySelectorAll('.kuale-branch-link').forEach(function(link) {
            link.addEventListener('click', function(e) {
                e.preventDefault();
                var branch = this.getAttribute('data-branch');
                var company = this.getAttribute('data-company');
                if (!branch || branch === 'N/A') {
                    modalTitle.textContent = company + ' - Tamaulipas, México';
                } else {
                    modalTitle.textContent = company + ' - ' + branch;
                }
                var encodedQuery = encodeURIComponent(company + ' Tamaulipas México');
                modalMap.src = 'https://maps.google.com/maps?q=' + encodedQuery + '&output=embed&hl=es&z=6&iwloc=B';
                modal.classList.add('is-open');
                modal._scrollY = window.scrollY;
                document.body.style.top = '-' + window.scrollY + 'px';
                document.body.style.position = 'fixed';
                document.body.style.width = '100%';
                document.body.classList.add('kuale-modal-open');
            });
        });

        if (modalClose) {
            modalClose.addEventListener('click', function() {
                modal.classList.remove('is-open');
                modalMap.src = '';
                document.body.style.position = '';
                document.body.style.top = '';
                document.body.style.width = '';
                document.body.classList.remove('kuale-modal-open');
                window.scrollTo({ top: modal._scrollY || 0, behavior: 'instant' });
            });
        }

        if (modal) {
            modal.addEventListener('click', function(e) {
                if (e.target === modal) {
                    modal.classList.remove('is-open');
                    modalMap.src = '';
                    document.body.style.position = '';
                    document.body.style.top = '';
                    document.body.style.width = '';
                    document.body.classList.remove('kuale-modal-open');
                    window.scrollTo({ top: modal._scrollY || 0, behavior: 'instant' });
                }
            });
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();

