form.script:
var _scrollY = 0;
function kualeOpenModal(modalEl) {
    modalEl.style.display = 'flex';
    modalEl.style.alignItems = window.innerWidth <= 767 ? 'flex-end' : 'center';
    _scrollY = window.scrollY;
    document.body.classList.add('kuale-modal-open');
}

function kualeCloseModal(modalEl) {
    modalEl.style.display = 'none';
    modalEl.style.alignItems = 'center';
    document.body.classList.remove('kuale-modal-open');
}

document.addEventListener('touchmove', function(e) {
    if (!document.body.classList.contains('kuale-modal-open')) return;

    var el = e.target;
    while (el && el !== document.body) {
        if (el.scrollHeight > el.clientHeight) {
            return; // tiene scroll, permitir
        }
        el = el.parentElement;
    }
    e.preventDefault();
}, { passive: false });

(function () {
    const LIST_HEIGHT_KEYBOARD = '120px';
    const LIST_HEIGHT_DEFAULT  = '320px';

    function isKeyboardOpen() {
        return window.visualViewport.height < window.screen.height * 0.65;
    }

    function setupModal(modalId, listId) {
        const modal = document.getElementById(modalId);
        if (!modal || !window.visualViewport) return;

        function adjust() {
            if (modal.style.display === 'none') return;
            const vv = window.visualViewport;

            modal.style.height = vv.height + 'px';
            modal.style.top    = vv.offsetTop + 'px';
            modal.style.left   = vv.offsetLeft + 'px';
            modal.style.width  = vv.width + 'px';

            const list = modal.querySelector('#' + listId);
            if (list) {
                list.style.maxHeight = isKeyboardOpen()
                    ? LIST_HEIGHT_KEYBOARD
                    : LIST_HEIGHT_DEFAULT;
            }
        }

        function reset() {
            modal.style.height = '';
            modal.style.top    = '';
            modal.style.left   = '';
            modal.style.width  = '';
            const list = modal.querySelector('#' + listId);
            if (list) list.style.maxHeight = LIST_HEIGHT_DEFAULT;
        }

        window.visualViewport.addEventListener('resize', adjust);
        window.visualViewport.addEventListener('scroll', adjust);

        new MutationObserver(() => {
            modal.style.display === 'none' ? reset() : adjust();
        }).observe(modal, { attributes: true, attributeFilter: ['style'] });
    }

    setupModal('abilityModal',    'ability_modal_list');
    setupModal('competencyModal', 'competency_modal_list');
})();

// Mostrar/ocultar campo "Otros" en Vive con
var livesWithHidden     = document.getElementById("lives_with_hidden");
var livesWithOtherSection = document.getElementById("lives_with_other_section");

if (livesWithHidden) {
    livesWithHidden.addEventListener("change", function() {
        if (livesWithHidden.value === "other") {
            livesWithOtherSection.style.display = "block";
        } else {
            livesWithOtherSection.style.display = "none";
            document.getElementById("lives_with_other").value = "";
        }
    });
}

(function () {
    function syncFormsCard() {
        var formsEl  = document.getElementById('forms');
        var section1 = document.getElementById('section1');
        if (!formsEl || !section1) return;

        var isSection1Active = !section1.classList.contains('d-none');
        formsEl.classList.toggle('kuale-forms--floating', !isSection1Active);
    }

    document.addEventListener('DOMContentLoaded', function () {
        syncFormsCard();

        var notice  = document.querySelector('#forms > .kuale-apply__notice');
        var section1 = document.getElementById('section1');
        if (notice && section1) {
            var clone = notice.cloneNode(true);
            clone.style.display = '';
            section1.insertBefore(clone, section1.firstChild);
        }

        var sections = document.querySelectorAll('.form-section');
        var observer = new MutationObserver(syncFormsCard);
        sections.forEach(function (sec) {
            observer.observe(sec, { attributes: true, attributeFilter: ['class'] });
        });
    });
})();

// Adicionales dropdowns
document.addEventListener('DOMContentLoaded', function () {

    function buildKualeDropdown(selectId, hiddenId, dropdownId, triggerId, labelId, menuId) {
        var selectEl = document.getElementById(selectId);
        var hiddenEl = document.getElementById(hiddenId);
        var dropdown = document.getElementById(dropdownId);
        var trigger  = document.getElementById(triggerId);
        var label    = document.getElementById(labelId);
        var menu     = document.getElementById(menuId);
        if (!selectEl || !menu) return;

        Array.from(selectEl.options).forEach(function (opt) {
            if (!opt.value) return;
            var item = document.createElement('div');
            item.className   = 'kuale-state-dropdown__option';
            item.textContent = opt.text;
            item.addEventListener('click', function () {
                hiddenEl.value    = opt.value;
                label.textContent = opt.text;
                dropdown.classList.remove('is-open');
                menu.querySelectorAll('.kuale-state-dropdown__option')
                    .forEach(function (o) { o.classList.remove('is-selected'); });
                item.classList.add('is-selected');
                hiddenEl.dispatchEvent(new Event('change'));
            });
            menu.appendChild(item);
        });

        var defaultOpt = Array.from(selectEl.options).find(function (o) { return o.selected; })
                    || Array.from(selectEl.options).find(function (o) { return o.value; });
        if (defaultOpt) {
            hiddenEl.value    = defaultOpt.value;
            label.textContent = defaultOpt.text;
            menu.querySelectorAll('.kuale-state-dropdown__option').forEach(function (i) {
                if (i.textContent === defaultOpt.text) i.classList.add('is-selected');
            });
        }

        trigger.addEventListener('click', function (e) {
            e.stopPropagation();
            dropdown.classList.toggle('is-open');
        });

        document.addEventListener('click', function () {
            dropdown.classList.remove('is-open');
        });
    }

    buildKualeDropdown('about_vacancy_select',       'about_vacancy_hidden',       'aboutVacancyDropdown',       'aboutVacancyTrigger',       'aboutVacancyLabel',       'aboutVacancyMenu');
    buildKualeDropdown('previous_experience_select', 'previous_experience_hidden', 'previousExperienceDropdown', 'previousExperienceTrigger', 'previousExperienceLabel', 'previousExperienceMenu');
    buildKualeDropdown('lives_with_select',          'lives_with_hidden',          'livesWithDropdown',          'livesWithTrigger',          'livesWithLabel',          'livesWithMenu');
    buildKualeDropdown('children_select',            'children_hidden',            'childrenDropdown',           'childrenTrigger',           'childrenLabel',           'childrenMenu');

    // Mostrar/ocultar número de hijos según selección + hacer obligatorio si Sí
    var childrenHidden = document.getElementById('children_hidden');
    if (childrenHidden) {
        childrenHidden.addEventListener('change', function () {
            var section = document.getElementById('number_children_section');
            var numberInput = document.getElementById('number_children');
            var hasChildren = this.value === 'true';
            if (section) section.style.display = hasChildren ? 'block' : 'none';
            if (numberInput) {
                if (hasChildren) {
                    numberInput.setAttribute('required', 'required');
                } else {
                    numberInput.removeAttribute('required');
                    numberInput.value = '';
                }
            }
        });
    }

    // Sobre la vacante — mostrar/ocultar campo "otro"
    var otherReasonSection = document.querySelector("[data-name='other_vacancy']");
    var otherReasonInput   = document.getElementById('other_reason');
    if (otherReasonSection) otherReasonSection.style.display = 'none';

    var aboutVacancyHidden = document.getElementById('about_vacancy_hidden');
    if (aboutVacancyHidden) {
        aboutVacancyHidden.addEventListener('change', function () {
            if (!otherReasonSection) return;
            if (this.value === 'other') {
                otherReasonSection.style.display = 'block';
                if (otherReasonInput) otherReasonInput.setAttribute('required', 'required');
            } else {
                otherReasonSection.style.display = 'none';
                if (otherReasonInput) otherReasonInput.removeAttribute('required');
            }
        });
    }
});

// Tipo de vialidad
document.addEventListener('DOMContentLoaded', function () {
    var selectEl = document.getElementById('type_road_select');
    var hiddenEl = document.getElementById('type_road');
    var dropdown = document.getElementById('typeRoadDropdown');
    var trigger  = document.getElementById('typeRoadTrigger');
    var label    = document.getElementById('typeRoadLabel');
    var menu     = document.getElementById('typeRoadMenu');

    if (!selectEl || !menu) return;

    Array.from(selectEl.options).forEach(function (opt) {
        if (!opt.value) return;
        var item = document.createElement('div');
        item.className   = 'kuale-state-dropdown__option';
        item.textContent = opt.text;
        item.addEventListener('click', function () {
            hiddenEl.value    = opt.value;
            label.textContent = opt.text;
            dropdown.classList.remove('is-open');
            menu.querySelectorAll('.kuale-state-dropdown__option')
                .forEach(function (o) { o.classList.remove('is-selected'); });
            item.classList.add('is-selected');
            hiddenEl.dispatchEvent(new Event('change'));
        });
        menu.appendChild(item);
    });

    // Seleccionar primer valor por defecto
    var firstOpt = Array.from(selectEl.options).find(function (o) { return o.value; });
    if (firstOpt) {
        hiddenEl.value    = firstOpt.value;
        label.textContent = firstOpt.text;
        var firstItem = menu.querySelector('.kuale-state-dropdown__option');
        if (firstItem) firstItem.classList.add('is-selected');
    }

    trigger.addEventListener('click', function (e) {
        e.stopPropagation();
        dropdown.classList.toggle('is-open');
    });

    document.addEventListener('click', function () {
        dropdown.classList.remove('is-open');
    });
});

//curp
function lockCurpFields() {
    var birthdateInput = document.getElementById('birthdate');
    if (birthdateInput) {
        birthdateInput.setAttribute('readonly', 'true');
        birthdateInput.style.backgroundColor = '#f5f5f5';
        birthdateInput.style.pointerEvents   = 'none';
        birthdateInput.style.cursor          = 'not-allowed';
    }
    var stateTrigger = document.getElementById('stateBirthTrigger');
    if (stateTrigger) {
        stateTrigger.style.pointerEvents = 'none';
        stateTrigger.style.opacity       = '0.6';
        stateTrigger.style.cursor        = 'not-allowed';
    }
}

function unlockCurpFields() {
    var birthdateInput = document.getElementById('birthdate');
    if (birthdateInput) {
        birthdateInput.removeAttribute('readonly');
        birthdateInput.style.backgroundColor = '';
        birthdateInput.style.pointerEvents   = '';
        birthdateInput.style.cursor          = '';
    }
    var stateTrigger = document.getElementById('stateBirthTrigger');
    if (stateTrigger) {
        stateTrigger.style.pointerEvents = '';
        stateTrigger.style.opacity       = '';
        stateTrigger.style.cursor        = '';
    }
}

function resetCurpFields() {
    var birthdateInput = document.getElementById('birthdate');
    if (birthdateInput) {
        birthdateInput.value = '';
        birthdateInput.dispatchEvent(new Event('change'));
    }
    var hiddenState = document.getElementById('state_birth_Select');
    var stateLabel  = document.getElementById('stateBirthLabel');
    var stateMenu   = document.getElementById('stateBirthMenu');
    if (hiddenState) hiddenState.value      = '';
    if (stateLabel)  stateLabel.textContent = '';
    if (stateMenu) {
        stateMenu.querySelectorAll('.kuale-state-dropdown__option')
            .forEach(function(o) { o.classList.remove('is-selected'); });
    }
    var hiddenCity = document.getElementById('birthplace_select');
    var cityLabel  = document.getElementById('cityBirthLabel');
    var cityMenu   = document.getElementById('cityBirthMenu');
    if (hiddenCity) hiddenCity.value      = '';
    if (cityLabel)  cityLabel.textContent = '';
    if (cityMenu)   cityMenu.innerHTML    = '';
    unlockCurpFields();
}

document.getElementById("curp").addEventListener("input", function() {
    this.value    = this.value.toUpperCase();
    var curpValue = this.value;
    var errorDiv  = document.getElementById('curp_error');
    var curpPattern = /^([A-Z][AEIOUX][A-Z]{2}\d{2}(?:0[1-9]|1[0-2])(?:0[1-9]|[12]\d|3[01])[HM](?:AS|B[CS]|C[CLMSH]|D[FG]|G[TR]|HG|JC|M[CNS]|N[ETL]|OC|PL|Q[TR]|S[PLR]|T[CSL]|VZ|YN|ZS)[B-DF-HJ-NP-TV-Z]{3}[A-Z\d])(\d)$/;

    if (curpValue.length === 0) { errorDiv.style.display = 'none'; resetCurpFields(); return; }

    if (curpValue.length < 18 || !curpPattern.test(curpValue)) {
        errorDiv.textContent   = "El CURP debe tener 18 caracteres y seguir el formato correcto.";
        errorDiv.style.display = 'block';
        unlockCurpFields(); return;
    }

    errorDiv.style.display = 'none';

    var yy      = curpValue.substring(4, 6);
    var mm      = curpValue.substring(6, 8);
    var dd      = curpValue.substring(8, 10);
    var yearNum = parseInt(yy, 10);
    var currentYY = new Date().getFullYear() % 100;
    var fullYear  = yearNum <= currentYY ? 2000 + yearNum : 1900 + yearNum;
    var dateStr   = fullYear + '-' + mm + '-' + dd;

    var birthdateInput = document.getElementById('birthdate');
    if (birthdateInput) {
        birthdateInput.value = dateStr;
        birthdateInput.dispatchEvent(new Event('change'));
    }

    var curpStateCode = curpValue.substring(11, 13);

    getSatData('estado_clave').then(function(estadoClave) {
        var entry = estadoClave[curpStateCode];
        if (!entry) { console.warn('Estado CURP no encontrado:', curpStateCode); return; }

        var stateName = entry.n;
        var stateCode = entry.c;

        var label       = document.getElementById('stateBirthLabel');
        var hiddenState = document.getElementById('state_birth_Select');
        if (label)       label.textContent = stateName;
        if (hiddenState) hiddenState.value = stateName; 
        console.log('[CURP] stateName:', stateName, '| stateCode:', stateCode);

        var menu = document.getElementById('stateBirthMenu');
        if (menu) {
            menu.querySelectorAll('.kuale-state-dropdown__option').forEach(function(o) {
                o.classList.remove('is-selected');
                if (o.textContent === stateName) o.classList.add('is-selected');
            });
        }

        if (window._loadCities) window._loadCities(stateCode);
        lockCurpFields();
    }).catch(function(err) { console.error('Error CURP:', err); });
});

// Estado civil
document.addEventListener('DOMContentLoaded', function () {
    var selectEl = document.getElementById('marital_status_select');
    var hiddenEl = document.getElementById('marital_status_hidden');
    var dropdown = document.getElementById('maritalStatusDropdown');
    var trigger  = document.getElementById('maritalStatusTrigger');
    var label    = document.getElementById('maritalStatusLabel');
    var menu     = document.getElementById('maritalStatusMenu');

    if (!selectEl || !menu) return;

    Array.from(selectEl.options).forEach(function (opt) {
        if (!opt.value) return;
        var item = document.createElement('div');
        item.className   = 'kuale-state-dropdown__option';
        item.textContent = opt.text;
        item.addEventListener('click', function () {
            hiddenEl.value    = opt.value;
            label.textContent = opt.text;
            dropdown.classList.remove('is-open');
            menu.querySelectorAll('.kuale-state-dropdown__option')
                .forEach(function (o) { o.classList.remove('is-selected'); });
            item.classList.add('is-selected');
            hiddenEl.dispatchEvent(new Event('change'));
        });
        menu.appendChild(item);
    });

    // Seleccionar el primer valor por defecto
    var firstOpt = Array.from(selectEl.options).find(function (o) { return o.value; });
    if (firstOpt) {
        hiddenEl.value    = firstOpt.value;
        label.textContent = firstOpt.text;
        var firstItem = menu.querySelector('.kuale-state-dropdown__option');
        if (firstItem) firstItem.classList.add('is-selected');
    }

    trigger.addEventListener('click', function (e) {
        e.stopPropagation();
        dropdown.classList.toggle('is-open');
    });

    document.addEventListener('click', function () {
        dropdown.classList.remove('is-open');
    });
});

//edad
document.getElementById("birthdate").addEventListener("change", function() {
    if (!this.value) {
        document.getElementById("age").value = '';
        return;
    }

    var birthdate = new Date(this.value);
    var today     = new Date();
    var age       = today.getFullYear() - birthdate.getFullYear();
    var m         = today.getMonth() - birthdate.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birthdate.getDate())) {
        age--;
    }
    document.getElementById("age").value = age;

    var ineModal    = document.getElementById('ineModal');
    var ineModalBtn = document.getElementById('ineModalBtn');

    if (age < 18) {
        if (ineModal) {
            ineModal.querySelector('h3').textContent = 'Menor de edad';
            ineModal.querySelector('p').innerHTML =
                'Si eres menor de edad, te sugerimos comunicarte con nosotros para que ' +
                'conozcas los requisitos para aplicar. <strong>(Tel.)</strong>';
            kualeOpenModal(ineModal);
        }
        if (ineModalBtn) {
            ineModalBtn.addEventListener("click", function() {
                window.location.href = "/jobs";
            });
        }
    } else {
       if (ineModal) kualeCloseModal(ineModal);
    }
});

//RFC
document.addEventListener("DOMContentLoaded", function() {
    var rfcTrack         = document.getElementById('rfcToggleTrack');
    var rfcSi            = document.getElementById('rfc_si');
    var rfcNo            = document.getElementById('rfc_no');
    var hiddenEl         = document.getElementById('has_rfc');
    var rfcNumberSection = document.getElementById('rfc_number_section');
    var rfcFilesSection  = document.getElementById('rfc_files_section');
    var rfcNumberInput   = document.getElementById('rfc_number');
    var rfcFilesInput    = document.getElementById('rfc_files');
    var rfcError         = document.getElementById('rfc_error');
    var rfcBox           = document.getElementById('rfc_upload_box');
    var rfcBoxClone      = rfcBox.cloneNode(true);

    function toggleRfcFields() {
        if (rfcSi.checked) {
            rfcTrack.classList.add('is-on');
            hiddenEl.value                 = 'yes';
            rfcNumberSection.style.display = 'block';
            rfcFilesSection.style.display  = 'block';
            rfcNumberInput.setAttribute('required', 'true');
        } else {
            rfcTrack.classList.remove('is-on');
            hiddenEl.value                 = 'no';
            rfcNumberSection.style.display = 'none';
            rfcFilesSection.style.display  = 'none';
            rfcNumberInput.removeAttribute('required');
            rfcFilesInput.removeAttribute('required');
            rfcNumberInput.value           = '';
            rfcError.style.display         = 'none';
        }
    }

    function validateRfc() {
        rfcNumberInput.value = rfcNumberInput.value.toUpperCase();
        var rfcValue   = rfcNumberInput.value;
        var rfcPattern = /^[A-ZÑ&]{3,4}\d{6}[A-Z\d]{3}$/;

        if (rfcValue.length === 0) { 
            rfcError.style.display = 'none'; 
            return; 
        }
        if (!rfcPattern.test(rfcValue)) {
            rfcError.style.color = '#6c757d';
            rfcError.textContent   = 'El RFC debe tener 12 o 13 caracteres y seguir el formato correcto.';
            rfcError.style.display = 'block';
        } else {
            rfcError.style.display = 'none';
        }
    }

    rfcFilesInput.addEventListener('change', function() {
        if (!this.files[0]) { return; }
        rfcBox.style.display = 'none';
    });

    var rfcParent   = rfcFilesInput.closest('#rfc_files_section');
    var rfcObserver = new MutationObserver(function() {
        var deleteBtn = rfcParent.querySelector('.o_file_delete');
        var uploadBtn = rfcParent.querySelector('.o_upload_btn');
        if (uploadBtn) uploadBtn.style.setProperty('display', 'none', 'important');

        // Ancho completo — siempre
        var fileWrap = rfcParent.querySelector('.o_file_wrap');
        if (fileWrap) {
            fileWrap.style.setProperty('width', '100%', 'important');
            fileWrap.style.setProperty('box-sizing', 'border-box', 'important');
        }

        if (deleteBtn && !rfcParent.querySelector('.kuale-preview-btn')) {
            var eyeBtn = document.createElement('button');
            eyeBtn.type = 'button';
            eyeBtn.className = 'kuale-preview-btn';
            eyeBtn.innerHTML = '👁';
            eyeBtn.style.cssText = 'background:none; border:none; cursor:pointer; font-size:16px; padding:0 4px;';
            eyeBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                var file = document.getElementById('rfc_files').files[0];
                if (file) window.open(URL.createObjectURL(file), '_blank');
            });
            deleteBtn.parentNode.insertBefore(eyeBtn, deleteBtn.nextSibling);
        }
        if (deleteBtn && !deleteBtn._rfcListened) {
            deleteBtn._rfcListened = true;
            deleteBtn.addEventListener('click', function() {
                setTimeout(function() {
                    var freshClone = rfcBoxClone.cloneNode(true);
                    freshClone.addEventListener('click', function() {
                        document.getElementById('rfc_files').click();
                    });
                    rfcBox.parentNode.replaceChild(freshClone, rfcBox);
                    rfcBox = freshClone;
                    var eyeOld = rfcParent.querySelector('.kuale-preview-btn');
                    if (eyeOld) eyeOld.remove();
                }, 150);
            });
        }
    });
    rfcObserver.observe(rfcParent, { childList: true, subtree: true });

    if (rfcTrack) {
        rfcTrack.addEventListener('click', function() {
            if (rfcSi.checked) { rfcNo.checked = true; }
            else               { rfcSi.checked = true; }
            toggleRfcFields();
        });
    }

    rfcNumberInput.addEventListener('input', validateRfc);
    toggleRfcFields();
});

// ── Helper compartido ──
function getSatData(key) {
    return new Promise(function(resolve, reject) {
        if (window._satData && window._satData[key]) { resolve(window._satData[key]); return; }
        if (!window._satData) window._satData = {};
        fetch('/reclutamiento__kuale/static/src/data/' + key + '.json')
            .then(function(r) { return r.json(); })
            .then(function(data) { window._satData[key] = data; resolve(data); })
            .catch(reject);
    });
}

// ── CP Domicilio ──
document.addEventListener('DOMContentLoaded', function() {
    var postalInput    = document.getElementById('postal_code');
    var stateInput     = document.getElementById('state');
    var munInput       = document.getElementById('municipality');
    var colonyHidden   = document.getElementById('colony');
    var colonyInput    = document.getElementById('colonyInput');
    var colonyMenu     = document.getElementById('colonyMenu');
    var colonyNotFound = document.getElementById('colony_not_found');

    if (!postalInput) return;

    var allColonias = [];

    // Precargar solo archivos pequeños en background
    getSatData('estados');
    getSatData('municipios');
    getSatData('estado_clave');

    function buildColonyMenu(filter) {
        if (!colonyMenu) return;
        colonyMenu.innerHTML = '';
        var filtered = filter
            ? allColonias.filter(function(c) { return c.toLowerCase().indexOf(filter.toLowerCase()) !== -1; })
            : allColonias;

        if (colonyNotFound) colonyNotFound.style.display = (filter && filtered.length === 0) ? 'block' : 'none';
        if (filtered.length === 0) { colonyMenu.style.display = 'none'; return; }

        filtered.forEach(function(nombre) {
            (function(text) {
                var opt = document.createElement('div');
                opt.textContent = text;
                opt.style.cssText = 'padding:10px 14px; cursor:pointer; font-size:14px;';
                opt.addEventListener('mouseenter', function() { opt.style.background = '#f5f5f5'; });
                opt.addEventListener('mouseleave', function() { opt.style.background = ''; });
                opt.addEventListener('mousedown', function(e) {
                    e.preventDefault();
                    colonyInput.value  = text;
                    colonyHidden.value = text;
                    colonyMenu.style.display = 'none';
                    if (colonyNotFound) colonyNotFound.style.display = 'none';
                });
                colonyMenu.appendChild(opt);
            })(nombre);
        });
        colonyMenu.style.display = 'block';
    }

    if (colonyInput) {
        colonyInput.addEventListener('input', function() {
            colonyHidden.value = colonyInput.value;
            if (allColonias.length) buildColonyMenu(colonyInput.value);
        });
        colonyInput.addEventListener('focus', function() {
            if (allColonias.length) buildColonyMenu(colonyInput.value);
        });
        colonyInput.addEventListener('blur', function() {
            setTimeout(function() { if (colonyMenu) colonyMenu.style.display = 'none'; }, 150);
            if (colonyInput.value) colonyHidden.value = colonyInput.value;
        });
    }

    function buscarCP(cp) {
        if (cp.length !== 5) {
            stateInput.value = ''; munInput.value = ''; colonyHidden.value = '';
            if (colonyInput)    colonyInput.value = '';
            if (colonyMenu)     colonyMenu.style.display = 'none';
            if (colonyNotFound) colonyNotFound.style.display = 'none';
            allColonias = []; return;
        }

        // Primero CP → estado/municipio
        getSatData('cp_estado_municipio').then(function(cpData) {
            var entry = cpData[cp];
            if (!entry) return;

            var stateCode = entry.e;
            var munCode   = entry.m;

            // Estado y municipio en paralelo (ya cacheados)
            Promise.all([getSatData('estados'), getSatData('municipios')]).then(function(results) {
                if (!stateInput.value) {
                    var est = results[0].find(function(e) { return e.c === stateCode; });
                    if (est) stateInput.value = est.n;
                }
                if (!munInput.value) {
                    var muns = results[1][stateCode] || [];
                    var mun  = muns.find(function(m) { return m.c === munCode; });
                    if (mun) munInput.value = mun.n;
                }
            });

            // Colonias por separado — no bloquea
            getSatData('colonias').then(function(coloniasData) {
                allColonias = coloniasData[cp] || [];
                colonyHidden.value = '';
                if (colonyInput)    colonyInput.value = '';
                if (colonyMenu)     colonyMenu.innerHTML = '';
                if (colonyNotFound) colonyNotFound.style.display = 'none';
            });
        }).catch(function(err) { console.error('Error CP:', err); });
    }

    postalInput.addEventListener('input', function() {
        var cp = postalInput.value.replace(/\D/g, '').slice(0, 5);
        postalInput.value = cp;
        buscarCP(cp);
    });

    document.addEventListener('click', function(e) {
        if (colonyMenu && colonyInput && !colonyInput.contains(e.target) && !colonyMenu.contains(e.target)) {
            colonyMenu.style.display = 'none';
        }
    });

    setTimeout(function() {
        var cp = postalInput.value.replace(/\D/g, '').slice(0, 5);
        if (cp.length === 5) buscarCP(cp);
    }, 800);
});

