//números telefónicos
document.addEventListener('DOMContentLoaded', function() {
    var mobileInput = document.getElementById('partner_mobile');
    var phoneInput  = document.getElementById('desk_phone');
    var mobileError = document.getElementById('mobile_error');
    var phoneError  = document.getElementById('phone_error');

    function formatPhone(val) {
        val = (val || '').replace(/\D/g, '').substring(0, 10);
        if (val.length === 0)  return '';
        if (val.length <= 3)  return '(' + val;
        if (val.length <= 6)  return '(' + val.substring(0,3) + ')-' + val.substring(3);
        return '(' + val.substring(0,3) + ')-' + val.substring(3,6) + '-' + val.substring(6);
    }

    function applyPhoneMask(input) {
        input.addEventListener('input', function() {
            input.value = formatPhone(input.value);
        });
    }

    function validatePhoneNumber(inputElement, errorElement, minLength, maxLength) {
        inputElement.addEventListener('input', function() {
            var digits = inputElement.value.replace(/\D/g, '');
            if (digits.length === 0) {
                errorElement.style.display     = 'none';
                inputElement.style.borderColor = '';
            } else if (digits.length < minLength || digits.length > maxLength) {
                errorElement.style.display     = 'block';
                inputElement.style.borderColor = 'red';
            } else {
                errorElement.style.display     = 'none';
                inputElement.style.borderColor = '';
            }
        });
    }

    applyPhoneMask(mobileInput);
    applyPhoneMask(phoneInput);

    validatePhoneNumber(mobileInput, mobileError, 10, 10);
    validatePhoneNumber(phoneInput,  phoneError,  7,  10);

    var phoneVal = mobileInput ? mobileInput.getAttribute('data-phone') : '';
    var formattedPhone = phoneVal ? formatPhone(phoneVal) : '';

    if (mobileInput && formattedPhone) {
        mobileInput.value = formattedPhone;

        var observer = new MutationObserver(function() {
            if (mobileInput.value === '' && formattedPhone) {
                mobileInput.value = formattedPhone;
            }
        });
        observer.observe(mobileInput, { attributes: true, attributeFilter: ['value'] });

        var attempts = 0;
        var interval = setInterval(function() {
            attempts++;
            if (mobileInput.value === '' && formattedPhone) {
                mobileInput.value = formattedPhone;
            }
            // Dejar de vigilar después de 3 segundos
            if (attempts > 30) {
                clearInterval(interval);
                observer.disconnect();
            }
        }, 100);
    }
});

// Estudios dropdowns
document.addEventListener('DOMContentLoaded', function () {

    function buildKualeDropdown(selectId, hiddenId, dropdownId, triggerId, labelId, menuId) {
        var selectEl = document.getElementById(selectId);
        var hiddenEl = document.getElementById(hiddenId);
        var dropdown = document.getElementById(dropdownId);
        var trigger  = document.getElementById(triggerId);
        var label    = document.getElementById(labelId);
        var menu     = document.getElementById(menuId);

        if (!selectEl || !menu) return;

        Array.from(selectEl.options).forEach(function (opt) {
            if (!opt.value) return;
            var item = document.createElement('div');
            item.className   = 'kuale-state-dropdown__option';
            item.textContent = opt.text;
            item.addEventListener('click', function () {
                hiddenEl.value    = opt.value;
                label.textContent = opt.text;
                dropdown.classList.remove('is-open');
                menu.querySelectorAll('.kuale-state-dropdown__option')
                    .forEach(function (o) { o.classList.remove('is-selected'); });
                item.classList.add('is-selected');
                hiddenEl.dispatchEvent(new Event('change'));
            });
            menu.appendChild(item);
        });

        var defaultOpt = Array.from(selectEl.options).find(function (o) { return o.selected; })
                    || Array.from(selectEl.options).find(function (o) { return o.value; });
        if (defaultOpt) {
            hiddenEl.value    = defaultOpt.value;
            label.textContent = defaultOpt.text;
            menu.querySelectorAll('.kuale-state-dropdown__option').forEach(function (i) {
                if (i.textContent === defaultOpt.text) i.classList.add('is-selected');
            });
        }

        trigger.addEventListener('click', function (e) {
            e.stopPropagation();
            dropdown.classList.toggle('is-open');
        });

        document.addEventListener('click', function () {
            dropdown.classList.remove('is-open');
        });
    }

    // Solo dos dropdowns — se elimina el r2
    buildKualeDropdown('scholarship_Related_select', 'scholarship_Related', 'scholarshipDropdown',       'scholarshipTrigger',       'scholarshipLabel',       'scholarshipMenu');
    buildKualeDropdown('academic_situation_select',  'academic_situation',  'academicSituationDropdown', 'academicSituationTrigger', 'academicSituationLabel', 'academicSituationMenu');
});

// Estudios
document.addEventListener("DOMContentLoaded", function () {
    var isStudyingSelect    = document.getElementById("is_studying");
    var isStudyingTrack     = document.getElementById("isStudyingToggleTrack");
    var isStudyingSi        = document.getElementById("is_studying_si");
    var isStudyingNo        = document.getElementById("is_studying_no");
    var scholarshipSelect   = document.getElementById("scholarship_Related");
    var scheduleBtnSection  = document.getElementById("schedule_btn_section");
    var scheduleModal       = document.getElementById("scheduleModal");
    var openScheduleBtn     = document.getElementById("open_schedule_modal");
    var saveScheduleBtn     = document.getElementById("save_schedule");
    var cancelScheduleBtn   = document.getElementById("cancel_schedule");
    var scheduleSummary     = document.getElementById("schedule_summary");
    var scheduleTags        = document.getElementById("schedule_tags");
    var scheduleWarning     = document.getElementById("schedule_warning");
    var slot3Licenciatura   = document.getElementById("slot3_licenciatura");
    var slot3Situacion      = document.getElementById("slot3_situacion");  
    var careerSection       = document.getElementById("career_section");
    var careerLabel         = document.getElementById("career_label");
    var careerInput         = document.getElementById("career");
    var specificDegreeInput = document.getElementById("specific_degree");
    var academicSit         = document.getElementById("academic_situation"); // único hidden input

    var days = [
        { label: "Lun", start: "schedule_monday_start",    end: "schedule_monday_end",    day: "monday" },
        { label: "Mar", start: "schedule_tuesday_start",   end: "schedule_tuesday_end",   day: "tuesday" },
        { label: "Mié", start: "schedule_wednesday_start", end: "schedule_wednesday_end", day: "wednesday" },
        { label: "Jue", start: "schedule_thursday_start",  end: "schedule_thursday_end",  day: "thursday" },
        { label: "Vie", start: "schedule_friday_start",    end: "schedule_friday_end",    day: "friday" },
        { label: "Sáb", start: "schedule_saturday_start",  end: "schedule_saturday_end",  day: "saturday" },
        { label: "Dom", start: "schedule_sunday_start",    end: "schedule_sunday_end",    day: "sunday" }
    ];

    if (scheduleModal) document.body.appendChild(scheduleModal);

    function resetSchedule() {
        days.forEach(function (d) {
            var s     = document.querySelector("[name='" + d.start + "']");
            var e     = document.querySelector("[name='" + d.end + "']");
            var check = scheduleModal.querySelector(".day-available-check[data-day='" + d.day + "']");
            if (s) { s.value = ""; s.disabled = false; s.style.opacity = "1"; s.style.background = ""; s.style.borderColor = ""; }
            if (e) { e.value = ""; e.disabled = false; e.style.opacity = "1"; e.style.background = ""; e.style.borderColor = ""; }
            if (check) check.checked = true;
        });
        scheduleTags.innerHTML        = "";
        scheduleSummary.style.display = "none";
        openScheduleBtn.style.display = "block";
        scheduleWarning.style.display = "none";
        openScheduleBtn.style.border       = "none";
        openScheduleBtn.style.borderRadius = "999px";
        var scheduleFilled = document.getElementById("schedule_filled");
        if (scheduleFilled) {
            scheduleFilled.value = "";
            scheduleFilled.removeAttribute("required");
        }
    }

    document.querySelectorAll(".day-available-check").forEach(function (checkbox) {
        checkbox.addEventListener("change", function () {
            var day    = this.getAttribute("data-day");
            var inputs = scheduleModal.querySelectorAll(".day-time-input[data-day='" + day + "']");
            inputs.forEach(function (input) {
                if (checkbox.checked) {
                    input.disabled         = false;
                    input.style.opacity    = "1";
                    input.style.background = "";
                } else {
                    input.disabled         = true;
                    input.value            = "";
                    input.style.opacity    = "0.4";
                    input.style.background = "#f0f0f0";
                }
            });
        });
    });

    openScheduleBtn.addEventListener("click", function () {
        kualeOpenModal(scheduleModal);
    });

    cancelScheduleBtn.addEventListener("click", function () {
        kualeCloseModal(scheduleModal);
    });

    saveScheduleBtn.addEventListener("click", function () {
        var allFilled = true;
        days.forEach(function (d) {
            var check = scheduleModal.querySelector(".day-available-check[data-day='" + d.day + "']");
            var s     = document.querySelector("[name='" + d.start + "']");
            var e     = document.querySelector("[name='" + d.end + "']");
            if (check.checked) {
                if (!s.value || !e.value) {
                    allFilled           = false;
                    s.style.borderColor = !s.value ? "#FA0000" : "";
                    e.style.borderColor = !e.value ? "#FA0000" : "";
                } else {
                    s.style.borderColor = "";
                    e.style.borderColor = "";
                }
            } else {
                s.value = ""; e.value = "";
                s.style.borderColor = ""; e.style.borderColor = "";
            }
        });

        if (!allFilled) return;

        scheduleTags.innerHTML = "";
        days.forEach(function (d) {
            var check = scheduleModal.querySelector(".day-available-check[data-day='" + d.day + "']");
            if (!check.checked) return;
            var s   = document.querySelector("[name='" + d.start + "']").value;
            var e   = document.querySelector("[name='" + d.end + "']").value;
            var tag = document.createElement("span");
            tag.style.cssText = "background:#FA0000; color:#fff; border-radius:999px; padding:4px 12px; font-size:13px; font-weight:600; white-space:nowrap;";
            tag.textContent   = d.label + ": " + s + " - " + e;
            scheduleTags.appendChild(tag);
        });

        scheduleSummary.style.display = "block";
        openScheduleBtn.style.display = "none";
        scheduleWarning.style.display = "none";
        kualeCloseModal(scheduleModal);
        openScheduleBtn.style.border       = "none";
        openScheduleBtn.style.borderRadius = "999px";
        var scheduleFilled = document.getElementById("schedule_filled");
        if (scheduleFilled) {
            scheduleFilled.value = "filled";
            scheduleFilled.dispatchEvent(new Event("change"));
        }
    });

    window.validateSchedule = function () {
        if (isStudyingSelect.value !== "yes") return true;
        var filled = days.every(function (d) {
            var check = scheduleModal.querySelector(".day-available-check[data-day='" + d.day + "']");
            if (!check.checked) return true;
            return document.querySelector("[name='" + d.start + "']").value
                && document.querySelector("[name='" + d.end + "']").value;
        });
        if (!filled) {
            scheduleWarning.style.display      = "block";
            openScheduleBtn.style.border       = "2px solid #FFA500";
            openScheduleBtn.style.borderRadius = "999px";
        }
        return filled;
    };

    function isLicenciatura() {
        var label = document.getElementById("scholarshipLabel");
        return label && label.textContent.trim() === "Licenciatura";
    }

    function updateLayout() {
        var studying       = isStudyingSelect.value === "yes";
        var licenciatura   = isLicenciatura();
        var scheduleFilled = document.getElementById("schedule_filled");

        // slot3_licenciatura: visible siempre que el nivel sea Licenciatura
        slot3Licenciatura.style.display = licenciatura ? "block" : "none";
        if (licenciatura) {
            specificDegreeInput.setAttribute("required", "");
        } else {
            specificDegreeInput.removeAttribute("required");
        }

        // Situación académica: único div, siempre habilitado y visible
        slot3Situacion.style.display = "block";
        academicSit.disabled         = false;

        if (studying) {
            // Carrera/especialidad visible con label adaptado
            careerSection.style.display = "block";
            careerLabel.textContent     = "¿Qué estudias?";
            careerInput.placeholder     = "Ej. Medicina, Derecho, etc.";
            careerInput.setAttribute("required", "");

            // Horario obligatorio
            scheduleBtnSection.style.display = "block";
            if (scheduleFilled) scheduleFilled.setAttribute("required", "");
        } else {
            resetSchedule();
            scheduleBtnSection.style.display = "none";
            if (scheduleFilled) scheduleFilled.removeAttribute("required");

            // Carrera solo visible si es Licenciatura y no estudia actualmente
            careerSection.style.display = licenciatura ? "block" : "none";
            if (licenciatura) {
                careerLabel.textContent = "Carrera o especialidad";
                careerInput.placeholder = "Ej. Ingeniería";
                careerInput.setAttribute("required", "");
            } else {
                careerInput.removeAttribute("required");
            }
        }
    }

    isStudyingSelect.addEventListener("change", updateLayout);
    scholarshipSelect.addEventListener("change", updateLayout);

    if (isStudyingTrack) {
        isStudyingTrack.addEventListener('click', function () {
            if (isStudyingSi.checked) {
                isStudyingNo.checked   = true;
                isStudyingSelect.value = 'no';
            } else {
                isStudyingSi.checked   = true;
                isStudyingSelect.value = 'yes';
            }
            isStudyingTrack.classList.toggle('is-on', isStudyingSi.checked);
            isStudyingSelect.dispatchEvent(new Event('change'));
        });
    }

    // Estado inicial: No estudia
    isStudyingNo.checked   = true;
    isStudyingSelect.value = 'no';
    isStudyingTrack.classList.remove('is-on');
    updateLayout();
});

// Experiencia
document.addEventListener("DOMContentLoaded", function () {

    function buildKualeDropdown(selectId, hiddenId, dropdownId, triggerId, labelId, menuId) {
        var selectEl = document.getElementById(selectId);
        var hiddenEl = document.getElementById(hiddenId);
        var dropdown = document.getElementById(dropdownId);
        var trigger  = document.getElementById(triggerId);
        var label    = document.getElementById(labelId);
        var menu     = document.getElementById(menuId);
        if (!selectEl || !menu) return;

        Array.from(selectEl.options).forEach(function (opt) {
            if (!opt.value) return;
            var item = document.createElement('div');
            item.className   = 'kuale-state-dropdown__option';
            item.textContent = opt.text;
            item.addEventListener('click', function () {
                hiddenEl.value    = opt.value;
                label.textContent = opt.text;
                dropdown.classList.remove('is-open');
                menu.querySelectorAll('.kuale-state-dropdown__option')
                    .forEach(function (o) { o.classList.remove('is-selected'); });
                item.classList.add('is-selected');
                hiddenEl.dispatchEvent(new Event('change'));
            });
            menu.appendChild(item);
        });

        var defaultOpt = Array.from(selectEl.options).find(function (o) { return o.selected; })
                    || Array.from(selectEl.options).find(function (o) { return o.value; });
        if (defaultOpt) {
            hiddenEl.value    = defaultOpt.value;
            label.textContent = defaultOpt.text;
            menu.querySelectorAll('.kuale-state-dropdown__option').forEach(function (i) {
                if (i.textContent === defaultOpt.text) i.classList.add('is-selected');
            });
        }

        trigger.addEventListener('click', function (e) {
            e.stopPropagation();
            dropdown.classList.toggle('is-open');
        });

        document.addEventListener('click', function () {
            dropdown.classList.remove('is-open');
        });
    }

    buildKualeDropdown('has_experience', 'has_experience_hidden', 'hasExperienceDropdown', 'hasExperienceTrigger', 'hasExperienceLabel', 'hasExperienceMenu');

    var hasExperienceSelect  = document.getElementById("has_experience_hidden");
    var experienceFields     = document.getElementById("experience_fields");
    var experienceActionBtns = document.getElementById("experience_action_btns");
    var experienceModal      = document.getElementById("experienceModal");
    var btnAdd               = document.getElementById("btn_add_experience");
    var btnDelete            = document.getElementById("btn_delete_experience");
    var tbody                = document.getElementById("experience_tbody");
    var hiddenInputs         = document.getElementById("experience_hidden_inputs");
    var saveBtn              = document.getElementById("save_experience");
    var cancelBtn            = document.getElementById("cancel_experience");
    var fPosition            = document.getElementById("exp_modal_position");
    var fSalary              = document.getElementById("exp_modal_salary");
    var fCompany             = document.getElementById("exp_modal_company");
    var fCity                = document.getElementById("exp_modal_city");
    var fFunctions           = document.getElementById("exp_modal_functions");
    var fSupervisor          = document.getElementById("exp_modal_supervisor");
    var fReference           = document.getElementById("exp_modal_reference");
    var fReferencePhone      = document.getElementById("exp_modal_reference_phone");
    var fDateIn              = document.getElementById("exp_modal_date_in");
    var fDateOut             = document.getElementById("exp_modal_date_out");
    var fReason              = document.getElementById("exp_modal_reason");
    var expCurrentlyTrack    = document.getElementById("expCurrentlyTrack");
    var expDateOutSection    = document.getElementById("exp_date_out_section");
    var expReasonSection     = document.getElementById("exp_reason_section");
    var expCurrently         = false;
    var experiences          = [];
    var editingIndex         = null;

    if (experienceModal) document.body.appendChild(experienceModal);
    var experienceRequiredFields = experienceFields.querySelectorAll("input, select");

    // Máscara teléfono referencia
    fReferencePhone.addEventListener('input', function() {
        var val = fReferencePhone.value.replace(/\D/g, '').substring(0, 10);
        if (val.length === 0)      { fReferencePhone.value = ''; }
        else if (val.length <= 3)  { fReferencePhone.value = '(' + val; }
        else if (val.length <= 6)  { fReferencePhone.value = '(' + val.substring(0,3) + ')-' + val.substring(3); }
        else                       { fReferencePhone.value = '(' + val.substring(0,3) + ')-' + val.substring(3,6) + '-' + val.substring(6); }
    });

    // Toggle actualmente
    function setCurrently(val) {
        expCurrently = val;
        if (val) {
            expCurrentlyTrack.classList.add('is-on');
            expDateOutSection.style.display = "none";
            expReasonSection.style.display  = "none";
            fDateOut.value                  = "";
            fReason.value                   = "";
        } else {
            expCurrentlyTrack.classList.remove('is-on');
            expDateOutSection.style.display = "block";
            expReasonSection.style.display  = "block";
        }
    }

    expCurrentlyTrack.addEventListener('click', function() {
        setCurrently(!expCurrently);
    });

    function toggleExperienceFields() {
        if (hasExperienceSelect.value === "yes") {
            experienceFields.style.display     = "block";
            experienceActionBtns.style.display = "flex";
            experienceRequiredFields.forEach(function (field) {
                field.setAttribute("required", "required");
            });
        } else {
            experienceFields.style.display     = "none";
            experienceActionBtns.style.display = "none";
            experienceRequiredFields.forEach(function (field) {
                field.removeAttribute("required");
            });
        }
    }
    hasExperienceSelect.addEventListener("change", toggleExperienceFields);
    toggleExperienceFields();

    function clearModal() {
        fPosition.value       = "";
        fSalary.value         = "";
        fCompany.value        = "";
        fCity.value           = "";
        fFunctions.value      = "";
        fSupervisor.value     = "";
        fReference.value      = "";
        fReferencePhone.value = "";
        fDateIn.value         = "";
        fDateOut.value        = "";
        fReason.value         = "";
        editingIndex          = null;
        setCurrently(false);
        [fPosition, fSalary, fCompany, fCity, fFunctions,
        fSupervisor, fReference, fReferencePhone,
        fDateIn, fDateOut, fReason].forEach(function (f) {
            f.style.borderColor = "";
        });
    }

    function openModal(index) {
        clearModal();
        if (index !== undefined) {
            var e             = experiences[index];
            fPosition.value       = e.position      || "";
            fSalary.value         = e.salary         || "";
            fCompany.value        = e.company        || "";
            fCity.value           = e.city           || "";
            fFunctions.value      = e.functions      || "";
            fSupervisor.value     = e.supervisor     || "";
            fReference.value      = e.reference      || "";
            fReferencePhone.value = e.referencePhone || "";
            fDateIn.value         = e.dateIn         || "";
            fDateOut.value        = e.dateOut        || "";
            fReason.value         = e.reason         || "";
            editingIndex          = index;
            setCurrently(e.currently || false);
        }
        kualeOpenModal(experienceModal);
    }

    function closeModal() {
        clearModal();
        kualeCloseModal(experienceModal);
    }

    function validate() {
        var valid = true;
        var requiredInputs = [fPosition, fSalary, fCompany, fCity, fDateIn];
        requiredInputs.forEach(function (f) {
            if (!f.value.trim()) { f.style.borderColor = "#FA0000"; valid = false; }
            else { f.style.borderColor = ""; }
        });
        if (!fFunctions.value.trim()) { fFunctions.style.borderColor = "#FA0000"; valid = false; }
        else { fFunctions.style.borderColor = ""; }
        if (!expCurrently) {
            if (!fDateOut.value) { fDateOut.style.borderColor = "#FA0000"; valid = false; }
            else { fDateOut.style.borderColor = ""; }
            if (!fReason.value.trim()) { fReason.style.borderColor = "#FA0000"; valid = false; }
            else { fReason.style.borderColor = ""; }
        }
        return valid;
    }

    function updateExpFilled() {
        var expFilled = document.getElementById("experience_filled");
        if (expFilled) {
            expFilled.value = experiences.length > 0 ? "filled" : "";
            expFilled.dispatchEvent(new Event("change", { bubbles: true }));
        }
    }

    function renderTable() {
        tbody.innerHTML        = "";
        hiddenInputs.innerHTML = "";
        if (experiences.length === 0) {
            var tr = document.createElement("tr");
            tr.innerHTML = "<td colspan='4' style='text-align:center; padding:16px; color:#aaa; font-style:italic;'>Sin experiencias agregadas</td>";
            tbody.appendChild(tr);
            btnDelete.style.display = "none";
            updateExpFilled();
            return;
        }
        experiences.forEach(function (e, i) {
            var idx        = i + 1;
            var checkStyle = "width:15px;height:15px;cursor:pointer;accent-color:#FA0000";
            var checkInput = "<input type='checkbox' class='exp-check' data-index='" + i + "' style='" + checkStyle + "'/>";
            var tr = document.createElement("tr");
            tr.style.cssText = "border-bottom:1px solid #eee; cursor:pointer;";
            tr.innerHTML =
                "<td style='text-align:center; padding:8px 12px;'>" + checkInput               + "</td>" +
                "<td style='text-align:center; padding:8px 12px;'>" + (e.supervisor     || "-") + "</td>" +
                "<td style='text-align:center; padding:8px 12px;'>" + (e.reference      || "-") + "</td>" +
                "<td style='text-align:center; padding:8px 12px;'>" + (e.referencePhone || "-") + "</td>";
            tr.addEventListener("click", function (ev) {
                if (ev.target.classList.contains("exp-check")) return;
                openModal(i);
            });
            tbody.appendChild(tr);
            hiddenInputs.innerHTML +=
                "<input type='hidden' name='positionE"       + idx + "' value='" + (e.position      || "") + "'/>" +
                "<input type='hidden' name='salaryE"         + idx + "' value='" + (e.salary         || "") + "'/>" +
                "<input type='hidden' name='companyE"        + idx + "' value='" + (e.company        || "") + "'/>" +
                "<input type='hidden' name='cityE"           + idx + "' value='" + (e.city           || "") + "'/>" +
                "<input type='hidden' name='functionsE"      + idx + "' value='" + (e.functions      || "") + "'/>" +
                "<input type='hidden' name='supervisorE"     + idx + "' value='" + (e.supervisor     || "") + "'/>" +
                "<input type='hidden' name='referenceE"      + idx + "' value='" + (e.reference      || "") + "'/>" +
                "<input type='hidden' name='referencePhoneE" + idx + "' value='" + (e.referencePhone || "") + "'/>" +
                "<input type='hidden' name='periodEIn"       + idx + "' value='" + (e.dateIn         || "") + "'/>" +
                "<input type='hidden' name='periodEOut"      + idx + "' value='" + (e.dateOut        || "") + "'/>" +
                "<input type='hidden' name='currently"       + idx + "' value='" + (e.currently ? "on" : "") + "'/>" +
                "<input type='hidden' name='reasonE"         + idx + "' value='" + (e.reason         || "") + "'/>";
        });
        updateExpFilled();
        updateDeleteBtn();
    }

    function updateDeleteBtn() {
        var checked = tbody.querySelectorAll(".exp-check:checked");
        btnDelete.style.display = checked.length > 0 ? "block" : "none";
    }

    tbody.addEventListener("change", function (e) {
        if (e.target.classList.contains("exp-check")) updateDeleteBtn();
    });

    btnAdd.addEventListener("click", function () { openModal(); });
    cancelBtn.addEventListener("click", closeModal);

    saveBtn.addEventListener("click", function () {
        if (!validate()) return;
        var entry = {
            position:       fPosition.value.trim(),
            salary:         fSalary.value.trim(),
            company:        fCompany.value.trim(),
            city:           fCity.value.trim(),
            functions:      fFunctions.value.trim(),
            supervisor:     fSupervisor.value.trim(),
            reference:      fReference.value.trim(),
            referencePhone: fReferencePhone.value.trim(),
            dateIn:         fDateIn.value,
            dateOut:        expCurrently ? new Date().toISOString().split('T')[0] : fDateOut.value,
            currently:      expCurrently,
            reason:         expCurrently ? "" : fReason.value.trim()
        };
        if (editingIndex !== null) {
            experiences[editingIndex] = entry;
        } else {
            experiences.push(entry);
        }
        renderTable();
        closeModal();
    });

    btnDelete.addEventListener("click", function () {
        var checked  = tbody.querySelectorAll(".exp-check:checked");
        var toDelete = [];
        checked.forEach(function (cb) {
            toDelete.push(parseInt(cb.getAttribute("data-index")));
        });
        toDelete.sort(function (a, b) { return b - a; });
        toDelete.forEach(function (idx) { experiences.splice(idx, 1); });
        renderTable();
    });

    renderTable();
});

//NSS
document.addEventListener("DOMContentLoaded", function() {
    var nssTrack      = document.getElementById('nssToggleTrack');
    var nssSi         = document.getElementById('nss_si');
    var nssNo         = document.getElementById('nss_no');
    var hiddenEl      = document.getElementById('has_social_security');
    var nssSection    = document.getElementById('social_security_number_section');
    var nssInput      = document.getElementById('social_security_number');
    var nssFilesDiv   = document.getElementById('nss_files_section');
    var nssFilesInput = document.getElementById('nss_files');
    var nssErrorDiv   = document.getElementById('nss_error');
    var nssBox        = document.getElementById('nss_upload_box');
    var nssBoxClone   = nssBox.cloneNode(true);

    function validateNss(nss) {
        if (nss.length !== 11 || isNaN(nss)) return false;
        var sum = 0, double = false;
        for (var i = nss.length - 1; i >= 0; i--) {
            var digit = parseInt(nss[i], 10);
            if (double) { digit *= 2; if (digit > 9) digit -= 9; }
            sum += digit;
            double = !double;
        }
        return sum % 10 === 0;
    }

    function toggleNssFields() {
        if (nssSi.checked) {
            nssTrack.classList.add('is-on');
            hiddenEl.value            = 'yes';
            nssSection.style.display  = 'block';
            nssFilesDiv.style.display = 'block';
            nssInput.setAttribute('required', 'true');
        } else {
            nssTrack.classList.remove('is-on');
            hiddenEl.value            = 'no';
            nssSection.style.display  = 'none';
            nssFilesDiv.style.display = 'none';
            nssInput.removeAttribute('required');
            nssFilesInput.removeAttribute('required');
            nssInput.value            = '';
            nssErrorDiv.style.display = 'none';
        }
    }

    nssFilesInput.addEventListener('change', function() {
        if (!this.files[0]) { return; }
        nssBox.style.display = 'none';
    });

    var nssParent   = nssFilesInput.closest('#nss_files_section');
    var nssObserver = new MutationObserver(function() {
        var deleteBtn = nssParent.querySelector('.o_file_delete');
        var uploadBtn = nssParent.querySelector('.o_upload_btn');
        if (uploadBtn) uploadBtn.style.setProperty('display', 'none', 'important');

        var fileWrap = nssParent.querySelector('.o_file_wrap');
        if (fileWrap) {
            fileWrap.style.setProperty('width', '100%', 'important');
            fileWrap.style.setProperty('box-sizing', 'border-box', 'important');
        }

        if (deleteBtn && !nssParent.querySelector('.kuale-preview-btn')) {
            var eyeBtn = document.createElement('button');
            eyeBtn.type = 'button';
            eyeBtn.className = 'kuale-preview-btn';
            eyeBtn.innerHTML = '👁';
            eyeBtn.style.cssText = 'background:none; border:none; cursor:pointer; font-size:16px; padding:0 4px;';
            eyeBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                var file = document.getElementById('nss_files').files[0];
                if (file) window.open(URL.createObjectURL(file), '_blank');
            });
            deleteBtn.parentNode.insertBefore(eyeBtn, deleteBtn.nextSibling);
        }
        if (deleteBtn && !deleteBtn._nssListened) {
            deleteBtn._nssListened = true;
            deleteBtn.addEventListener('click', function() {
                setTimeout(function() {
                    var freshClone = nssBoxClone.cloneNode(true);
                    freshClone.addEventListener('click', function() {
                        document.getElementById('nss_files').click();
                    });
                    nssBox.parentNode.replaceChild(freshClone, nssBox);
                    nssBox = freshClone;
                    var eyeOld = nssParent.querySelector('.kuale-preview-btn');
                    if (eyeOld) eyeOld.remove();
                }, 150);
            });
        }
    });
    nssObserver.observe(nssParent, { childList: true, subtree: true });

    if (nssTrack) {
        nssTrack.addEventListener('click', function() {
            if (nssSi.checked) { nssNo.checked = true; }
            else               { nssSi.checked = true; }
            toggleNssFields();
        });
    }

    nssInput.addEventListener('input', function() {
        if (nssInput.value.length === 0) { nssErrorDiv.style.display = 'none'; return; }
        if (!validateNss(nssInput.value)) {
            nssErrorDiv.style.color = '#6c757d';
            nssErrorDiv.textContent = 'NSS inválido. Debe ser un número de 11 dígitos.';
            nssErrorDiv.style.display = 'block';
        } else {
            nssErrorDiv.style.display = 'none';
        }
    });

    toggleNssFields();
});

// Otros estudios
document.addEventListener("DOMContentLoaded", function () {
    var otherStudyModal = document.getElementById("otherStudyModal");
    var btnAdd          = document.getElementById("btn_add_other_study");
    var btnDelete       = document.getElementById("btn_delete_other_study");
    var tbody           = document.getElementById("other_studies_tbody");
    var tableWrapper    = document.getElementById("other_studies_table_wrapper");
    var hiddenInputs    = document.getElementById("other_studies_hidden_inputs");
    var modalName       = document.getElementById("modal_name_study");
    var modalSchool     = document.getElementById("modal_school_studies");
    var modalHasDoc     = document.getElementById("modal_has_document");
    var modalDocType    = document.getElementById("modal_document_type");
    var modalDocSection = document.getElementById("modal_doc_type_section");
    var saveBtn         = document.getElementById("save_other_study");
    var cancelBtn       = document.getElementById("cancel_other_study");
    var editingIndex    = document.getElementById("modal_editing_index");
    var modalTitle      = otherStudyModal.querySelector("h4");

    var studies = [];

    if (otherStudyModal) document.body.appendChild(otherStudyModal);

    modalHasDoc.addEventListener("change", function () {
        modalDocSection.style.display = this.value === "yes" ? "block" : "none";
        if (this.value !== "yes") modalDocType.value = "";
    });

    function openModal(idx) {
        modalName.value               = "";
        modalSchool.value             = "";
        modalHasDoc.value             = "no";
        modalDocType.value            = "";
        modalDocSection.style.display = "none";
        modalName.style.borderColor   = "";
        modalSchool.style.borderColor = "";
        editingIndex.value            = idx !== undefined ? idx : -1;

        if (idx !== undefined) {
            var s = studies[idx];
            modalTitle.textContent        = "Editar estudio";
            modalName.value               = s.name;
            modalSchool.value             = s.school;
            modalHasDoc.value             = s.hasDoc;
            modalDocType.value            = s.docType;
            modalDocSection.style.display = s.hasDoc === "yes" ? "block" : "none";
        } else {
            modalTitle.textContent = "Agregar estudio";
        }

        kualeOpenModal(otherStudyModal);
    }

    function closeModal() {
        kualeCloseModal(otherStudyModal);
    }

    function validate() {
        var valid = true;
        if (!modalName.value.trim()) {
            modalName.style.borderColor = "#FA0000";
            valid = false;
        } else {
            modalName.style.borderColor = "";
        }
        if (!modalSchool.value.trim()) {
            modalSchool.style.borderColor = "#FA0000";
            valid = false;
        } else {
            modalSchool.style.borderColor = "";
        }
        if (modalHasDoc.value === "yes" && !modalDocType.value.trim()) {
            modalDocType.style.borderColor = "#FA0000";
            valid = false;
        } else {
            modalDocType.style.borderColor = "";
        }
        return valid;
    }

    function renderTable() {
        tbody.innerHTML        = "";
        hiddenInputs.innerHTML = "";
        tableWrapper.style.display = "block";

        if (studies.length === 0) {
            var tr = document.createElement("tr");
            tr.innerHTML = '<td colspan="5" style="text-align:center; padding:16px; color:#aaa; font-style:italic;">Sin estudios agregados</td>';
            tbody.appendChild(tr);
            btnDelete.style.display = "none";
            return;
        }

        studies.forEach(function (s, i) {
            var idx        = i + 1;
            var hasDocText = (s.hasDoc === "yes") ? "Sí" : "No";
            var checkStyle = "width:15px;height:15px;cursor:pointer;accent-color:#FA0000";
            var checkInput = '<input type="checkbox" class="other-study-check" data-index="' + i + '" style="' + checkStyle + '"/>';

            var tr = document.createElement("tr");
            tr.style.borderBottom = "1px solid #eee";
            tr.style.cursor       = "pointer";
            tr.setAttribute("data-index", i);
            tr.innerHTML =
                '<td style="text-align:center; padding:8px 12px;">' + checkInput          + '</td>' +
                '<td style="text-align:center; padding:8px 12px;">' + (s.name    || "-") + '</td>' +
                '<td style="text-align:center; padding:8px 12px;">' + (s.school  || "-") + '</td>' +
                '<td style="text-align:center; padding:8px 12px;">' + hasDocText          + '</td>' +
                '<td style="text-align:center; padding:8px 12px;">' + (s.docType || "-") + '</td>';
            tbody.appendChild(tr);

            hiddenInputs.innerHTML +=
                '<input type="hidden" name="name_study'     + idx + '" value="' + s.name    + '"/>' +
                '<input type="hidden" name="school_studies' + idx + '" value="' + s.school  + '"/>' +
                '<input type="hidden" name="has_document'   + idx + '" value="' + s.hasDoc  + '"/>' +
                '<input type="hidden" name="document_type'  + idx + '" value="' + s.docType + '"/>';
        });

        updateDeleteBtn();
    }

    function updateDeleteBtn() {
        var checked = tbody.querySelectorAll(".other-study-check:checked");
        btnDelete.style.display = checked.length > 0 ? "block" : "none";
    }

    tbody.addEventListener("change", function (e) {
        if (e.target.classList.contains("other-study-check")) updateDeleteBtn();
    });

    tbody.addEventListener("click", function (e) {
        if (e.target.classList.contains("other-study-check")) return;
        var tr = e.target.closest("tr[data-index]");
        if (tr) openModal(parseInt(tr.getAttribute("data-index")));
    });

    btnAdd.addEventListener("click", function () { openModal(); });
    cancelBtn.addEventListener("click", closeModal);

    saveBtn.addEventListener("click", function () {
        if (!validate()) return;

        var idx = parseInt(editingIndex.value);
        var entry = {
            id:      idx >= 0 ? studies[idx].id : new Date().getTime(),
            name:    modalName.value.trim(),
            school:  modalSchool.value.trim(),
            hasDoc:  modalHasDoc.value,
            docType: modalDocType.value.trim()
        };

        if (idx >= 0) {
            studies[idx] = entry;
        } else {
            studies.push(entry);
        }

        renderTable();
        closeModal();
    });

    btnDelete.addEventListener("click", function () {
        var checked  = tbody.querySelectorAll(".other-study-check:checked");
        var toDelete = [];
        checked.forEach(function (cb) {
            toDelete.push(parseInt(cb.getAttribute("data-index")));
        });
        toDelete.sort(function (a, b) { return b - a; });
        toDelete.forEach(function (idx) { studies.splice(idx, 1); });
        renderTable();
    });

    renderTable();
});

//Licencia
function initLicenciaBlock() {
    var licenciaTrack   = document.getElementById('licenciaToggleTrack');
    var licenciaSi      = document.getElementById('licencia_si');
    var licenciaNo      = document.getElementById('licencia_no');
    var numberSection   = document.getElementById('driver_license_number_section');
    var validitySection = document.getElementById('driver_license_validity_section');
    var filesSection    = document.getElementById('driver_files_section');
    var driverInput     = document.getElementById('driver_files');
    var driverBox       = document.getElementById('driver_upload_box');

    // Si aún no están en el DOM, no hacer nada (el observer lo reintentará)
    if (!driverBox || !driverInput || !licenciaTrack || !licenciaSi || !licenciaNo) {
        return false;
    }

    var driverBoxClone = driverBox.cloneNode(true);

    function toggleLicenciaFields() {
        if (licenciaSi.checked) {
            licenciaTrack.classList.add('is-on');
            if (numberSection)   numberSection.style.display   = 'block';
            if (validitySection) validitySection.style.display = 'block';
            if (filesSection)    filesSection.style.display    = 'block';
        } else {
            licenciaTrack.classList.remove('is-on');
            if (numberSection)   numberSection.style.display   = 'none';
            if (validitySection) validitySection.style.display = 'none';
            if (filesSection)    filesSection.style.display    = 'none';
        }
    }

    driverInput.addEventListener('change', function() {
        if (!this.files[0]) return;
        driverBox.style.display = 'none';
    });

    var driverParent = driverInput.closest('#driver_files_section');
    var driverObserver = new MutationObserver(function() {
        var deleteBtn = driverParent.querySelector('.o_file_delete');
        var uploadBtn = driverParent.querySelector('.o_upload_btn');
        if (uploadBtn) uploadBtn.style.setProperty('display', 'none', 'important');

        var fileWrap = driverParent.querySelector('.o_file_wrap');
        if (fileWrap) {
            fileWrap.style.setProperty('width', '100%', 'important');
            fileWrap.style.setProperty('box-sizing', 'border-box', 'important');
        }

        if (deleteBtn && !driverParent.querySelector('.kuale-preview-btn')) {
            var eyeBtn = document.createElement('button');
            eyeBtn.type = 'button';
            eyeBtn.className = 'kuale-preview-btn';
            eyeBtn.innerHTML = '👁';
            eyeBtn.style.cssText = 'background:none; border:none; cursor:pointer; font-size:16px; padding:0 4px;';
            eyeBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                var file = document.getElementById('driver_files').files[0];
                if (file) window.open(URL.createObjectURL(file), '_blank');
            });
            deleteBtn.parentNode.insertBefore(eyeBtn, deleteBtn.nextSibling);
        }

        if (deleteBtn && !deleteBtn._driverListened) {
            deleteBtn._driverListened = true;
            deleteBtn.addEventListener('click', function() {
                setTimeout(function() {
                    var freshClone = driverBoxClone.cloneNode(true);
                    freshClone.addEventListener('click', function() {
                        document.getElementById('driver_files').click();
                    });
                    driverBox.parentNode.replaceChild(freshClone, driverBox);
                    driverBox = freshClone;
                    var eyeOld = driverParent.querySelector('.kuale-preview-btn');
                    if (eyeOld) eyeOld.remove();
                }, 150);
            });
        }
    });

    driverObserver.observe(driverParent, { childList: true, subtree: true });

    if (licenciaTrack) {
        licenciaTrack.addEventListener('click', function() {
            if (licenciaSi.checked) {
                licenciaNo.checked = true;
            } else {
                licenciaSi.checked = true;
            }
            toggleLicenciaFields();
        });
    }

    toggleLicenciaFields();
    return true; // éxito, ya no necesitamos el observer externo
}

// Intentar inicializar en DOMContentLoaded
document.addEventListener("DOMContentLoaded", function() {
    if (initLicenciaBlock()) return;

    // Si no estaba listo, observar el body hasta que aparezca
    var bodyObserver = new MutationObserver(function() {
        if (initLicenciaBlock()) {
            bodyObserver.disconnect(); // dejar de observar una vez iniciado
        }
    });

    bodyObserver.observe(document.body, { childList: true, subtree: true });
});

