            ineTypeMenu.querySelectorAll('.kuale-state-dropdown__option')
                .forEach(function(o) { o.classList.remove('is-selected'); });
            item.classList.add('is-selected');
            ineTypeSelected.dispatchEvent(new Event('change'));
            ineDocumentSection.style.display = "block";
            ineValiditySection.style.display = "block";
        });
        ineTypeMenu.appendChild(item);
    });

    ineTypeTrigger.addEventListener("click", function(e) {
        e.stopPropagation();
        ineTypeDropdown.classList.toggle("is-open");
    });

    document.addEventListener("click", function() {
        ineTypeDropdown.classList.remove("is-open");
    });

    ineInput.addEventListener('change', function() {
        if (!this.files[0]) return;
        ineBox.style.display = 'none';
    });

    var ineParent   = ineInput.closest('#ine_document_section');
    var ineObserver = new MutationObserver(function() {
        var deleteBtn = ineParent.querySelector('.o_file_delete');
        var uploadBtn = ineParent.querySelector('.o_upload_btn');
        if (uploadBtn) uploadBtn.style.setProperty('display', 'none', 'important');
        if (deleteBtn && !ineParent.querySelector('.kuale-preview-btn')) {
            var eyeBtn = document.createElement('button');
            eyeBtn.type = 'button';
            eyeBtn.className = 'kuale-preview-btn';
            eyeBtn.innerHTML = '👁';
            eyeBtn.style.cssText = 'background:none; border:none; cursor:pointer; font-size:16px; padding:0 4px;';
            eyeBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                var file = document.getElementById('ine_document').files[0];
                if (file) window.open(URL.createObjectURL(file), '_blank');
            });
            deleteBtn.parentNode.insertBefore(eyeBtn, deleteBtn.nextSibling);
        }
        if (deleteBtn && !deleteBtn._ineListened) {
            deleteBtn._ineListened = true;
            deleteBtn.addEventListener('click', function() {
                setTimeout(function() {
                    var freshClone = ineBoxClone.cloneNode(true);
                    freshClone.addEventListener('click', function() {
                        document.getElementById('ine_document').click();
                    });
                    ineBox.parentNode.replaceChild(freshClone, ineBox);
                    ineBox = freshClone;
                    var eyeOld = ineParent.querySelector('.kuale-preview-btn');
                    if (eyeOld) eyeOld.remove();
                }, 150);
            });
        }
    });
    ineObserver.observe(ineParent, { childList: true, subtree: true });

    function toggleIdentificationFields() {
        if (ineSi.checked) {
            ineTrack.classList.add('is-on');
            ineTypeSection.style.display     = "block";
            ineDocumentSection.style.display = "none";
            ineValiditySection.style.display = "none";
            ineTypeSelected.setAttribute('required', '');
            if (ineNoModal) kualeCloseModal(ineNoModal);
        } else {
            ineTrack.classList.remove('is-on');
            ineTypeSection.style.display     = "none";
            ineDocumentSection.style.display = "none";
            ineValiditySection.style.display = "none";
            ineTypeLabel.textContent         = "Selecciona tipo";
            ineTypeSelected.value            = "";
            ineTypeDropdown.classList.remove("is-open");
            ineTypeMenu.querySelectorAll('.kuale-state-dropdown__option')
                .forEach(function(o) { o.classList.remove('is-selected'); });
            ineTypeSelected.removeAttribute('required');
            if (ineNoModal) kualeOpenModal(ineNoModal);
        }
    }

    if (ineTrack) {
        ineTrack.addEventListener('click', function() {
            if (ineSi.checked) { ineNo.checked = true; }
            else               { ineSi.checked = true; }
            toggleIdentificationFields();
        });
    }

    ineSi.checked = true;
    toggleIdentificationFields();
});

