// Cargar estados y municipios
document.addEventListener('DOMContentLoaded', function() {
    var hiddenState  = document.getElementById('state_birth_Select');
    var dropdown     = document.getElementById('stateBirthDropdown');
    var trigger      = document.getElementById('stateBirthTrigger');
    var label        = document.getElementById('stateBirthLabel');
    var menu         = document.getElementById('stateBirthMenu');
    var hiddenCity   = document.getElementById('birthplace_select');
    var cityDropdown = document.getElementById('cityBirthDropdown');
    var cityTrigger  = document.getElementById('cityBirthTrigger');
    var cityLabel    = document.getElementById('cityBirthLabel');
    var cityMenu     = document.getElementById('cityBirthMenu');

    if (!dropdown) return;

    function getSatData(key) {
        return new Promise(function(resolve, reject) {
            if (window._satData && window._satData[key]) { resolve(window._satData[key]); return; }
            if (!window._satData) window._satData = {};
            fetch('/reclutamiento__kuale/static/src/data/' + key + '.json')
                .then(function(r) { return r.json(); })
                .then(function(data) { window._satData[key] = data; resolve(data); })
                .catch(reject);
        });
    }

    function loadCities(stateCode) {
        if (!cityMenu) return;
        cityMenu.innerHTML    = '';
        hiddenCity.value      = '';
        cityLabel.textContent = 'Selecciona tu ciudad de nacimiento';

        getSatData('municipios').then(function(municipios) {
            var list = municipios[stateCode] || [];
            list.forEach(function(mun) {
                (function(val, text) {
                    var opt = document.createElement('div');
                    opt.className   = 'kuale-state-dropdown__option';
                    opt.textContent = text;
                    opt.addEventListener('click', function() {
                        hiddenCity.value = text;
                        cityLabel.textContent = text;
                        cityDropdown.classList.remove('is-open');
                        cityMenu.querySelectorAll('.kuale-state-dropdown__option')
                            .forEach(function(o) { o.classList.remove('is-selected'); });
                        opt.classList.add('is-selected');
                    });
                    cityMenu.appendChild(opt);
                })(mun.c, mun.n);
            });
        });
    }

    window._loadCities = loadCities;

    getSatData('estados').then(function(estados) {
        estados.forEach(function(est) {
            (function(val, text) {
                var opt = document.createElement('div');
                opt.className   = 'kuale-state-dropdown__option';
                opt.textContent = text;
                opt.addEventListener('click', function() {
                    hiddenState.value = text;
                    label.textContent = text;
                    dropdown.classList.remove('is-open');
                    menu.querySelectorAll('.kuale-state-dropdown__option')
                        .forEach(function(o) { o.classList.remove('is-selected'); });
                    opt.classList.add('is-selected');
                    loadCities(val);
                });
                menu.appendChild(opt);
            })(est.c, est.n);
        });
    });

    trigger.addEventListener('click', function(e) {
        e.stopPropagation();
        dropdown.classList.toggle('is-open');
    });

    cityTrigger.addEventListener('click', function(e) {
        e.stopPropagation();
        if (!hiddenState.value) return;
        cityDropdown.classList.toggle('is-open');
    });

    document.addEventListener('click', function() {
        dropdown.classList.remove('is-open');
        cityDropdown.classList.remove('is-open');
    });
});

