    if (knowledgeModal) document.body.appendChild(knowledgeModal);
    if (toolModal)      document.body.appendChild(toolModal);

    // ── Selector ──────────────────────────────────────────
    btnAdd.addEventListener("click", function () {
        editingIndex = -1;
        kualeOpenModal(selectorModal);
    });

    document.getElementById("btn_selector_cancel").addEventListener("click", function () {
        kualeCloseModal(selectorModal);
    });

    document.getElementById("btn_selector_knowledge").addEventListener("click", function () {
        kualeCloseModal(selectorModal);
        openKnowledgeModal();
    });

    document.getElementById("btn_selector_tool").addEventListener("click", function () {
        kualeCloseModal(selectorModal);
        openToolModal();
    });

    // ── Modal Conocimiento ─────────────────────────────────
    function openKnowledgeModal(idx) {
        modalKName.value             = "";
        modalKName.style.borderColor = "";

        if (idx !== undefined) {
            var k = items[idx];
            modalKTitle.textContent = "Editar conocimiento";
            modalKName.value        = k.name;
            editingIndex            = idx;
        } else {
            modalKTitle.textContent = "Agregar conocimiento";
        }
        kualeOpenModal(knowledgeModal);
    }

    cancelKBtn.addEventListener("click", function () {
        kualeCloseModal(knowledgeModal);
        kualeOpenModal(selectorModal);
    });

    saveKBtn.addEventListener("click", function () {
        if (!modalKName.value.trim()) { modalKName.style.borderColor = "#FA0000"; return; }
        modalKName.style.borderColor = "";

        var entry = {
            tipo: "Conocimiento",
            name: modalKName.value.trim()
        };
        if (editingIndex >= 0) { items[editingIndex] = entry; }
        else { items.push(entry); }
        renderTable();
        kualeCloseModal(knowledgeModal);
    });

    // ── Modal Herramienta ──────────────────────────────────
    function openToolModal(idx) {
        modalTName.value             = "";
        modalTName.style.borderColor = "";

        if (idx !== undefined) {
            var t = items[idx];
            modalTTitle.textContent = "Editar herramienta";
            modalTName.value        = t.name;
            editingIndex            = idx;
        } else {
            modalTTitle.textContent = "Agregar herramienta";
        }
        kualeOpenModal(toolModal);
    }

    cancelTBtn.addEventListener("click", function () {
        kualeCloseModal(toolModal);
        kualeOpenModal(selectorModal);
    });

    saveTBtn.addEventListener("click", function () {
        if (!modalTName.value.trim()) { modalTName.style.borderColor = "#FA0000"; return; }
        modalTName.style.borderColor = "";

        var entry = {
            tipo: "Herramienta",
            name: modalTName.value.trim()
        };
        if (editingIndex >= 0) { items[editingIndex] = entry; }
        else { items.push(entry); }
        renderTable();
        kualeCloseModal(toolModal);
    });

    // ── Tabla ──────────────────────────────────────────────
    function renderTable() {
        tbody.innerHTML        = "";
        hiddenInputs.innerHTML = "";

        if (items.length === 0) {
            var tr = document.createElement("tr");
            tr.innerHTML = '<td colspan="3" style="text-align:center; padding:16px; color:#aaa; font-style:italic;">Sin conocimientos o herramientas agregados</td>';
            tbody.appendChild(tr);
            btnDelete.style.display = "none";
            return;
        }

        items.forEach(function (k, i) {
            var idx        = i + 1;
            var checkStyle = "width:15px;height:15px;cursor:pointer;accent-color:#FA0000";
            var checkInput = '<input type="checkbox" class="knowledge-check" data-index="' + i + '" style="' + checkStyle + '"/>';
            var tr = document.createElement("tr");
            tr.style.borderBottom = "1px solid #eee";
            tr.style.cursor       = "pointer";
            tr.setAttribute("data-index", i);
            tr.innerHTML =
                '<td style="text-align:center; padding:8px 12px;">' + checkInput      + '</td>' +
                '<td style="text-align:center; padding:8px 12px;">' + (k.tipo || "-") + '</td>' +
                '<td style="text-align:center; padding:8px 12px;">' + (k.name || "-") + '</td>';
            tbody.appendChild(tr);

            hiddenInputs.innerHTML +=
                '<input type="hidden" name="knowledge_applicant_' + idx + '" value="' + k.name + '"/>' +
                '<input type="hidden" name="knowledge_type_'      + idx + '" value="' + k.tipo + '"/>';
        });

        updateDeleteBtn();
    }

    function updateDeleteBtn() {
        var checked = tbody.querySelectorAll(".knowledge-check:checked");
        btnDelete.style.display = checked.length > 0 ? "block" : "none";
    }

    tbody.addEventListener("change", function (e) {
        if (e.target.classList.contains("knowledge-check")) updateDeleteBtn();
    });

    tbody.addEventListener("click", function (e) {
        if (e.target.classList.contains("knowledge-check")) return;
        var tr = e.target.closest("tr[data-index]");
        if (!tr) return;
        var idx  = parseInt(tr.getAttribute("data-index"));
        var item = items[idx];
        editingIndex = idx;
        if (item.tipo === "Conocimiento") { openKnowledgeModal(idx); }
        else { openToolModal(idx); }
    });

    btnDelete.addEventListener("click", function () {
        var checked  = tbody.querySelectorAll(".knowledge-check:checked");
        var toDelete = [];
        checked.forEach(function (cb) {
            toDelete.push(parseInt(cb.getAttribute("data-index")));
        });
        toDelete.sort(function (a, b) { return b - a; });
        toDelete.forEach(function (idx) { items.splice(idx, 1); });
        renderTable();
    });

    renderTable();
});

// Idiomas
document.addEventListener("DOMContentLoaded", function () {
    var languageModal  = document.getElementById("languageModal");
    var btnAdd         = document.getElementById("btn_add_language");
    var btnDelete      = document.getElementById("btn_delete_language");
    var tbody          = document.getElementById("language_tbody");
    var hiddenInputs   = document.getElementById("language_hidden_inputs");
    var modalLang      = document.getElementById("modal_language_id");
    var modalLevel     = document.getElementById("modal_level_id");
    var saveBtn        = document.getElementById("save_language");
    var cancelBtn      = document.getElementById("cancel_language");
    var modalTitle     = document.getElementById("language_modal_title");

    var languages    = [];
    var editingIndex = -1;

    if (languageModal) document.body.appendChild(languageModal);

    function openModal(idx) {
        modalLang.selectedIndex      = 0;
        modalLevel.selectedIndex     = 0;
        modalLang.style.borderColor  = "";
        modalLevel.style.borderColor = "";
        editingIndex                 = idx !== undefined ? idx : -1;

        var errMsg = document.getElementById("lang_duplicate_error");
        if (errMsg) errMsg.textContent = "";

        if (idx !== undefined) {
            var l = languages[idx];
            modalTitle.textContent = "Editar idioma";
            for (var i = 0; i < modalLang.options.length; i++) {
                if (modalLang.options[i].value == l.langId) {
                    modalLang.selectedIndex = i; break;
                }
            }
            for (var j = 0; j < modalLevel.options.length; j++) {
                if (modalLevel.options[j].value == l.levelId) {
                    modalLevel.selectedIndex = j; break;
                }
            }
        } else {
            modalTitle.textContent = "Agregar idioma";
        }

        kualeOpenModal(languageModal);
    }

    function closeModal() {
        kualeCloseModal(languageModal);
    }

    function validate() {
        var valid = true;

        if (!modalLang.value) {
            modalLang.style.borderColor = "#FA0000";
            valid = false;
        } else {
            modalLang.style.borderColor = "";
        }

        if (!modalLevel.value) {
            modalLevel.style.borderColor = "#FA0000";
            valid = false;
        } else {
            modalLevel.style.borderColor = "";
        }

        if (!valid) return false;

        var duplicate = languages.some(function (l, i) {
            return l.langId == modalLang.value && i !== editingIndex;
        });

        if (duplicate) {
            modalLang.style.borderColor = "#FA0000";
            modalLang.title = "Este idioma ya fue agregado";
            var errMsg = document.getElementById("lang_duplicate_error");
            if (!errMsg) {
                errMsg = document.createElement("div");
                errMsg.id = "lang_duplicate_error";
                errMsg.style.cssText = "color:#FA0000; font-size:12px; margin-top:4px;";
                modalLang.parentNode.appendChild(errMsg);
            }
            errMsg.textContent = "Este idioma ya fue agregado.";
            return false;
        }

        var errMsg = document.getElementById("lang_duplicate_error");
        if (errMsg) errMsg.textContent = "";

        return true;
    }

    function renderTable() {
        tbody.innerHTML        = "";
        hiddenInputs.innerHTML = "";

        if (languages.length === 0) {
            var tr = document.createElement("tr");
            tr.innerHTML = '<td colspan="3" style="text-align:center; padding:16px; color:#aaa; font-style:italic;">Sin idiomas agregados</td>';
            tbody.appendChild(tr);
            btnDelete.style.display = "none";
            return;
        }

        languages.forEach(function (l, i) {
            var idx        = i + 1;
            var checkStyle = "width:15px;height:15px;cursor:pointer;accent-color:#FA0000";
            var checkInput = '<input type="checkbox" class="language-check" data-index="' + i + '" style="' + checkStyle + '"/>';

            var tr = document.createElement("tr");
            tr.style.borderBottom = "1px solid #eee";
            tr.style.cursor       = "pointer";
            tr.setAttribute("data-index", i);
            tr.innerHTML =
                '<td style="text-align:center; padding:8px 12px;">' + checkInput          + '</td>' +
                '<td style="text-align:center; padding:8px 12px;">' + (l.langText  || "-") + '</td>' +
                '<td style="text-align:center; padding:8px 12px;">' + (l.levelText || "-") + '</td>';
            tbody.appendChild(tr);

            hiddenInputs.innerHTML +=
                '<input type="hidden" name="language_id_' + idx + '" value="' + l.langId  + '"/>' +
                '<input type="hidden" name="level_id_'    + idx + '" value="' + l.levelId + '"/>';
        });

        updateDeleteBtn();
    }

    function updateDeleteBtn() {
        var checked = tbody.querySelectorAll(".language-check:checked");
        btnDelete.style.display = checked.length > 0 ? "block" : "none";
    }

    tbody.addEventListener("change", function (e) {
        if (e.target.classList.contains("language-check")) updateDeleteBtn();
    });

    tbody.addEventListener("click", function (e) {
        if (e.target.classList.contains("language-check")) return;
        var tr = e.target.closest("tr[data-index]");
        if (tr) openModal(parseInt(tr.getAttribute("data-index")));
    });

    btnAdd.addEventListener("click", function () { openModal(); });
    cancelBtn.addEventListener("click", closeModal);

    saveBtn.addEventListener("click", function () {
        if (!validate()) return;

        var langOpt  = modalLang.options[modalLang.selectedIndex];
        var levelOpt = modalLevel.options[modalLevel.selectedIndex];

        var entry = {
            id:        editingIndex >= 0 ? languages[editingIndex].id : new Date().getTime(),
            langId:    langOpt.value,
            langText:  langOpt.text,
            levelId:   levelOpt.value,
            levelText: levelOpt.text
        };

        if (editingIndex >= 0) {
            languages[editingIndex] = entry;
        } else {
            languages.push(entry);
        }

        renderTable();
        closeModal();
    });

    btnDelete.addEventListener("click", function () {
        var checked  = tbody.querySelectorAll(".language-check:checked");
        var toDelete = [];
        checked.forEach(function (cb) {
            toDelete.push(parseInt(cb.getAttribute("data-index")));
        });
        toDelete.sort(function (a, b) { return b - a; });
        toDelete.forEach(function (idx) { languages.splice(idx, 1); });
        renderTable();
    });

    renderTable();
});

// Competencias y Habilidades
document.addEventListener("DOMContentLoaded", function () {
    function getOptionsFromSelect(selectId) {
        var select  = document.getElementById(selectId);
        var options = [];
        if (!select) return options;
        for (var i = 0; i < select.options.length; i++) {
            options.push({ id: select.options[i].value, text: select.options[i].text });
        }
        return options;
    }
    function initTagField(config) {
        var tagsContainer = document.getElementById(config.tagsId);
        var hiddenCont    = document.getElementById(config.hiddenId);
        var modal         = document.getElementById(config.modalId);
        var modalList     = document.getElementById(config.modalListId);
        var modalSearch   = document.getElementById(config.modalSearchId);
        var btnAdd        = document.getElementById(config.btnAddId);
        var btnClose1     = document.getElementById(config.closeModalId);
        var btnClose2     = document.getElementById(config.closeModalBtnId);
        var selected      = [];
        function renderTags() {
            tagsContainer.innerHTML = "";
            hiddenCont.innerHTML   = "";
            selected.forEach(function (item, i) {
                var tag = document.createElement("span");
                tag.style.cssText = "display:inline-flex; align-items:center; gap:6px; background:#FA0000; color:#fff; border-radius:999px; padding:5px 14px; font-size:13px; font-weight:600;";
                var tagText = document.createElement("span");
                tagText.textContent = item.text;
                var tagX = document.createElement("button");
                tagX.type = "button";
                tagX.textContent = "x";
                tagX.style.cssText = "background:none; border:none; color:#fff; cursor:pointer; font-size:13px; font-weight:700; padding:0; line-height:1;";
                tagX.addEventListener("click", function () {
                    selected.splice(i, 1);
                    renderTags();
                    renderModalList(modalSearch.value.trim().toLowerCase());
                });
                tag.appendChild(tagText);
                tag.appendChild(tagX);
                tagsContainer.appendChild(tag);
                var hidden = document.createElement("input");
                hidden.type  = "hidden";
                hidden.name  = config.fieldName + "_" + (i + 1);
                hidden.value = item.id;
                hiddenCont.appendChild(hidden);
            });
        }
        function renderModalList(filter) {
            modalList.innerHTML = "";
            var opts = config.options.filter(function (o) {
                var matchFilter = !filter || o.text.toLowerCase().indexOf(filter) !== -1;
                return matchFilter;
            });
            if (opts.length === 0) {
                var empty = document.createElement("div");
                empty.style.cssText = "padding:16px 24px; color:#999; font-size:14px;";
                empty.textContent = "No se encontraron resultados";
                modalList.appendChild(empty);
                return;
            }
            opts.forEach(function (item) {
                var isSelected = selected.some(function (s) { return s.id == item.id; });
                var row = document.createElement("div");
                row.style.cssText = "display:flex; align-items:center; justify-content:space-between; padding:10px 24px; cursor:pointer; font-size:14px; border-bottom:1px solid #f5f5f5; transition:background 0.15s;";
                row.style.background = isSelected ? "#fff5f5" : "#fff";
                var rowText = document.createElement("span");
                rowText.textContent = item.text;
                rowText.style.flex = "1";
                var rowBadge = document.createElement("span");
                rowBadge.style.cssText = "font-size:12px; font-weight:700; border-radius:999px; padding:3px 12px; margin-left:8px; transition:all 0.15s;";
                if (isSelected) {
                    rowBadge.textContent = "Agregado ✓";
                    rowBadge.style.cssText += "background:#FA0000; color:#fff;";
                } else {
                    rowBadge.textContent = "+ Agregar";
                    rowBadge.style.cssText += "background:#f0f0f0; color:#333;";
                }
                row.appendChild(rowText);
                row.appendChild(rowBadge);
                row.addEventListener("mouseenter", function () {
                    if (!selected.some(function (s) { return s.id == item.id; })) {
                        row.style.background = "#fff5f5";
                    }
                });
                row.addEventListener("mouseleave", function () {
                    if (!selected.some(function (s) { return s.id == item.id; })) {
                        row.style.background = "#fff";
                    }
                });
                row.addEventListener("click", function () {
                    var idx = selected.findIndex(function (s) { return s.id == item.id; });
                    if (idx === -1) {
                        selected.push(item);
                    } else {
                        selected.splice(idx, 1);
                    }
                    renderTags();
                    renderModalList(modalSearch.value.trim().toLowerCase());
                });
                modalList.appendChild(row);
            });
        }
        function openModal() {
            modalSearch.value = "";
            renderModalList("");
            kualeOpenModal(modal);
        }
        function closeModal() {
            kualeCloseModal(modal);
        }
        btnAdd.addEventListener("click", openModal);
        btnClose1.addEventListener("click", closeModal);
        btnClose2.addEventListener("click", closeModal);
        modal.addEventListener("click", function (e) {
            if (e.target === modal) closeModal();
        });
        modalSearch.addEventListener("input", function () {
            renderModalList(this.value.trim().toLowerCase());
        });
        renderTags();
    }
    initTagField({
        tagsId:          "competencies_tags",
        hiddenId:        "competencies_hidden",
        modalId:         "competencyModal",
        modalListId:     "competency_modal_list",
        modalSearchId:   "competency_modal_search",
        btnAddId:        "btn_add_competency",
        closeModalId:    "close_competency_modal",
        closeModalBtnId: "close_competency_modal_btn",
        fieldName:       "competencies_ids",
        options:         getOptionsFromSelect("competencies_ids_select")
    });
    initTagField({
        tagsId:          "abilities_tags",
        hiddenId:        "abilities_hidden",
        modalId:         "abilityModal",
        modalListId:     "ability_modal_list",
        modalSearchId:   "ability_modal_search",
        btnAddId:        "btn_add_ability",
        closeModalId:    "close_ability_modal",
        closeModalBtnId: "close_ability_modal_btn",
        fieldName:       "ability_ids",
        options:         getOptionsFromSelect("ability_ids_select")
    });
});

// Aviso al recargar o cerrar la página
function beforeUnloadHandler(e) {
    e.preventDefault();
    e.returnValue = '';
}
window.addEventListener('beforeunload', beforeUnloadHandler);

// Bandera: solo enviar cuando el usuario confirmó
var kualeFormConfirmed = false;
var submitBtn = document.querySelector('button[type="submit"].kuale-btn-new--solid');

if (submitBtn) {
    submitBtn.addEventListener('click', function(e) {
        if (kualeFormConfirmed) return;

        var form = document.getElementById('hr_recruitment_form2');

        if (Object.keys(selectedBranches).length === 0) {
            var err = document.getElementById('branch_error');
            if (err) err.style.display = 'block';
            e.preventDefault();
            e.stopPropagation();
            return;
        }

        if (form && !form.checkValidity()) return;

        e.preventDefault();
        e.stopPropagation();
        kualeOpenModal(document.getElementById('kualeConfirmModal'));
    }, false);
}

document.getElementById('kualeConfirmCancel').addEventListener('click', function() {
   kualeCloseModal(document.getElementById('kualeConfirmModal'));
});

document.getElementById('kualeConfirmOk').addEventListener('click', function() {
    kualeCloseModal(document.getElementById('kualeConfirmModal'));

    // Mostrar pantalla de carga
    var loadingModal = document.getElementById('kualeLoadingModal');
    kualeOpenModal(loadingModal);

    // Bloquear botón de envío
    if (submitBtn) {
        submitBtn.disabled = true;
        submitBtn.style.opacity = '0.5';
        submitBtn.style.cursor = 'not-allowed';
    }

    window.removeEventListener('beforeunload', beforeUnloadHandler);

    // ── horario del modal al form ──────────────────────
    var scheduleNames = [
        'schedule_monday_start',    'schedule_monday_end',
        'schedule_tuesday_start',   'schedule_tuesday_end',
        'schedule_wednesday_start', 'schedule_wednesday_end',
        'schedule_thursday_start',  'schedule_thursday_end',
        'schedule_friday_start',    'schedule_friday_end',
        'schedule_saturday_start',  'schedule_saturday_end',
        'schedule_sunday_start',    'schedule_sunday_end',
    ];
    var form = document.getElementById('hr_recruitment_form2');
    scheduleNames.forEach(function(name) {
        var modalInput = document.querySelector("[name='" + name + "']");
        if (!modalInput) return;
        var old = form.querySelector("input[name='" + name + "'][type='hidden']");
        if (old) old.remove();
        if (modalInput.value) {
            var hidden = document.createElement('input');
            hidden.type  = 'hidden';
            hidden.name  = name;
            hidden.value = modalInput.value;
            form.appendChild(hidden);
        }
    });

    var jobIds = [];
    var reqIds = [];
    Object.values(selectedBranches).forEach(function(b) {
        if (b.isBolsa) {
            b.jobIds.forEach(function(jid, i) {
                jobIds.push(jid);
                reqIds.push(b.reqIds[i] || '');
            });
        } else {
            if (b.jobId) jobIds.push(b.jobId);
            reqIds.push(b.reqId || '');
        }
    });

    var total = jobIds.length;
    if (total === 0) {
        kualeCloseModal(loadingModal);
        return;
    }

    var csrfInput = document.querySelector('input[name="csrf_token"]');
    var csrf = csrfInput ? csrfInput.value : (typeof odoo !== 'undefined' && odoo.csrf_token ? odoo.csrf_token : '');

    function submitUno(index) {
        if (index >= total) {
            window.location.href = '/job-thank-you-r';
            return;
        }

        var fd = new FormData(form);
        fd.set('job_id', jobIds[index]);
        fd.set('requisition_id', reqIds[index] || '');

        // Marcar si esta postulación es de bolsa de trabajo
        var esBolsa = Object.values(selectedBranches).some(function(b) {
            return b.isBolsa && b.jobIds && b.jobIds.indexOf(jobIds[index]) !== -1;
        });
        fd.set('from_bolsa_trabajo', esBolsa ? 'True' : 'False');

        if (csrf) fd.set('csrf_token', csrf);

        fetch('/website/form3/hr.applicant', {
            method: 'POST',
            body: fd,
        })
        .then(function(response) {
            return response.text().then(function(text) {
                return { status: response.status, text: text };
            });
        })
        .then(function(result) {
            var parsed = null;
            try { parsed = JSON.parse(result.text); } catch(e) {}

            if (result.status !== 200 || (parsed && parsed.error)) {
                kualeCloseModal(loadingModal);
                if (submitBtn) {
                    submitBtn.disabled = false;
                    submitBtn.style.opacity = '1';
                    submitBtn.style.cursor = 'pointer';
                }
                console.error('Error:', parsed ? parsed.error : result.text.substring(0, 300));
                alert('Ocurrió un error al enviar. Por favor intenta de nuevo.');
                return;
            }
            setTimeout(function() { submitUno(index + 1); }, 500);
        })
        .catch(function(err) {
            kualeCloseModal(loadingModal);
            if (submitBtn) {
                submitBtn.disabled = false;
                submitBtn.style.opacity = '1';
                submitBtn.style.cursor = 'pointer';
            }
            console.error('Error de red:', err.message || String(err));
            alert('Error de conexión. Por favor intenta de nuevo.');
        });
    }

    submitUno(0);
});

//Familiares
document.addEventListener("DOMContentLoaded", function() {
    var selectEl  = document.getElementById("familiaresSelect");
    var hiddenEl  = document.getElementById("has_family_working_with_us");
    var dropdown  = document.getElementById("familiaresDropdown");
    var trigger   = document.getElementById("familiaresTrigger");
    var label     = document.getElementById("familiaresLabel");
    var menu      = document.getElementById("familiaresMenu");
    var nameInput = document.getElementById("family_worker_name");

    if (!selectEl || !menu) return;

    function toggleFamiliarFields() {
        if (hiddenEl.value === "yes") {
            nameInput.style.display = "block";
        } else {
            nameInput.style.display = "none";
            nameInput.value         = "";
        }
    }

    Array.from(selectEl.options).forEach(function(opt) {
        if (!opt.value) return;
        var item         = document.createElement("div");
        item.className   = "kuale-state-dropdown__option";
        item.textContent = opt.text;
        item.addEventListener("click", function() {
            hiddenEl.value    = opt.value;
            label.textContent = opt.text;
            dropdown.classList.remove("is-open");
            menu.querySelectorAll(".kuale-state-dropdown__option")
                .forEach(function(o) { o.classList.remove("is-selected"); });
            item.classList.add("is-selected");
            toggleFamiliarFields();
        });
        menu.appendChild(item);
    });

    // Seleccionar "No"
    var defaultOpt = Array.from(selectEl.options).find(function(o) { return o.selected; });
    if (defaultOpt) {
        hiddenEl.value    = defaultOpt.value;
        label.textContent = defaultOpt.text;
        menu.querySelectorAll(".kuale-state-dropdown__option").forEach(function(item) {
            if (item.textContent === defaultOpt.text) item.classList.add("is-selected");
        });
    }

    trigger.addEventListener("click", function(e) {
        e.stopPropagation();
        dropdown.classList.toggle("is-open");
    });
    document.addEventListener("click", function() {
        dropdown.classList.remove("is-open");
    });

    toggleFamiliarFields();
});

document.addEventListener('DOMContentLoaded', function () {
    const main = document.querySelector('#wrapwrap > main');
    if (main) {
        main.style.setProperty('min-height', '0px', 'important');

        const observer = new MutationObserver(function () {
            main.style.setProperty('min-height', '0px', 'important');
        });

        observer.observe(main, {
            attributes: true,
            attributeFilter: ['style']
        });
    }
});

// Curriculum
document.addEventListener("DOMContentLoaded", function() {
    var currInput = document.getElementById('recruitment6');
    var currBox   = document.getElementById('curriculum_upload_box');
    if (!currInput || !currBox) return;
    var currBoxClone = currBox.cloneNode(true);
    var currParent   = currInput.parentNode;

    currInput.addEventListener('change', function() {
        if (!this.files[0]) return;
        currBox.style.display = 'none';
    });

    var currObserver = new MutationObserver(function() {
        var deleteBtn = currParent.querySelector('.o_file_delete');
        var uploadBtn = currParent.querySelector('.o_upload_btn');
        if (uploadBtn) uploadBtn.style.setProperty('display', 'none', 'important');

        var fileWrap = currParent.querySelector('.o_file_wrap');
        if (fileWrap) {
            fileWrap.style.setProperty('width', '100%', 'important');
            fileWrap.style.setProperty('box-sizing', 'border-box', 'important');
        }

        var fileBlock = currParent.querySelector('.o_file_block');
        if (fileBlock) {
            fileBlock.style.setProperty('width', '100%', 'important');
            fileBlock.style.setProperty('max-width', '100%', 'important');
            fileBlock.style.setProperty('flex', '0 0 100%', 'important');
        }

        if (deleteBtn && !currParent.querySelector('.kuale-preview-btn')) {
            var eyeBtn = document.createElement('button');
            eyeBtn.type = 'button';
            eyeBtn.className = 'kuale-preview-btn';
            eyeBtn.innerHTML = '👁';
            eyeBtn.style.cssText = 'background:none; border:none; cursor:pointer; font-size:16px; padding:0 4px;';
            eyeBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                var file = document.getElementById('recruitment6').files[0];
                if (file) window.open(URL.createObjectURL(file), '_blank');
            });
            deleteBtn.parentNode.insertBefore(eyeBtn, deleteBtn.nextSibling);
        }

        if (deleteBtn && !deleteBtn._currListened) {
            deleteBtn._currListened = true;
            deleteBtn.addEventListener('click', function() {
                setTimeout(function() {
                    var freshClone = currBoxClone.cloneNode(true);
                    freshClone.addEventListener('click', function() {
                        document.getElementById('recruitment6').click();
                    });
                    currBox.parentNode.replaceChild(freshClone, currBox);
                    currBox = freshClone;
                    var eyeOld = currParent.querySelector('.kuale-preview-btn');
                    if (eyeOld) eyeOld.remove();
                }, 150);
            });
        }
    });
    currObserver.observe(currParent, { childList: true, subtree: true });
});

// ── Sucursales modal ──
var branchOverlay = document.getElementById('branchSelectOverlay');
var btnAddBranch = document.getElementById('btn_add_branch');
var branchSelectClose = document.getElementById('branchSelectClose');
var branchTags = document.getElementById('branch_tags');
var selectedBranches = {};

function updateRequisitionIds() {
    var reqIds = [];
    var jobIds = [];
    Object.values(selectedBranches).forEach(function(b) {
        if (b.isBolsa) {
            b.reqIds.forEach(function(r) { if (r) reqIds.push(r); });
            b.jobIds.forEach(function(j) { if (j) jobIds.push(j); });
        } else {
            if (b.reqId) reqIds.push(b.reqId);
            if (b.jobId) jobIds.push(b.jobId);
        }
    });
    var campoReq = document.getElementById('kuale_requisition_id');
    if (campoReq) campoReq.value = reqIds.join(',');
    var campoJob = document.getElementById('kuale_job_id_hidden');
    if (campoJob) campoJob.value = jobIds[0] || '';

    if (reqIds.length > 0) {
        var err = document.getElementById('branch_error');
        if (err) err.style.display = 'none';

        // ── Limpiar borde de error en branch_tags ──
        var tags = document.getElementById('branch_tags');
        if (tags) {
            tags.removeAttribute('data-kuale-error');
            tags.style.setProperty('border', '1.5px solid var(--kuale-border)', 'important');
            tags.style.setProperty('border-radius', 'var(--kuale-radius)', 'important');
        }
    }
}

function refreshBranchButtons() {
    document.querySelectorAll('.kuale-branch-select-btn').forEach(function(btn) {
        var jobId = btn.getAttribute('data-job-id');
        if (selectedBranches[jobId]) {
            btn.style.opacity = '0.4';
            btn.style.pointerEvents = 'none';
            btn.style.background = '#e0e0e0';
        } else {
            btn.style.opacity = '1';
            btn.style.pointerEvents = 'auto';
            btn.style.background = '#f5f5f5';
        }
    });
    // Bolsa de trabajo por sucursal
    document.querySelectorAll('.btn_bolsa_trabajo_item').forEach(function(btn) {
        var jobId = btn.getAttribute('data-bolsa-job-id');
        var key   = 'bolsa_' + jobId;
        if (selectedBranches[key]) {
            btn.style.opacity       = '0.4';
            btn.style.pointerEvents = 'none';
            btn.style.background    = '#e0e0e0';
        } else {
            btn.style.opacity       = '1';
            btn.style.pointerEvents = 'auto';
            btn.style.background    = '#fff5f5';
        }
    });
}

if (btnAddBranch) {
    btnAddBranch.addEventListener('click', function() {
        kualeOpenModal(branchOverlay);
        refreshBranchButtons();
    });
}

if (branchSelectClose) {
    branchSelectClose.addEventListener('click', function() {
        kualeCloseModal(branchOverlay);
    });
}

if (branchOverlay) {
    branchOverlay.addEventListener('click', function(e) {
        if (e.target === branchOverlay) kualeCloseModal(branchOverlay);
    });
}

document.querySelectorAll('.kuale-branch-select-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
        var reqId  = this.getAttribute('data-req-id');
        var jobId  = this.getAttribute('data-job-id');
        var branch = this.getAttribute('data-branch');

        if (selectedBranches[jobId]) return;

        selectedBranches[jobId] = { reqId: reqId, jobId: jobId, branch: branch };
        updateRequisitionIds();
        refreshBranchButtons();

        // Crear tag
        var tag = document.createElement('span');
        tag.setAttribute('data-job-id', jobId);
        tag.style.cssText = 'display:inline-flex; align-items:center; gap:6px; background:#fff5f5; color:#FA0000; border:1px solid #FA0000; border-radius:999px; padding:4px 12px; font-size:13px; font-weight:600; font-family:"Aloevera",system-ui,sans-serif;';
        tag.innerHTML = branch + ' ✕';
        tag.querySelector('button').addEventListener('click', function() {
            delete selectedBranches[jobId];
            tag.remove();
            updateRequisitionIds();
            refreshBranchButtons();
        });
        branchTags.appendChild(tag);

        kualeCloseModal(branchOverlay);
    });
});

// ── Bolsa de trabajo ──
document.querySelectorAll('.btn_bolsa_trabajo_item').forEach(function(btn) {
    btn.addEventListener('click', function() {
        var jobId  = this.getAttribute('data-bolsa-job-id');
        var reqId  = this.getAttribute('data-bolsa-req-id');
        var branch = this.getAttribute('data-bolsa-branch-name');
        var key    = 'bolsa_' + jobId;

        if (selectedBranches[key]) return;

        selectedBranches[key] = {
            reqId:   reqId,
            jobId:   jobId,
            branch:  branch,
            isBolsa: true,
            reqIds:  [reqId],
            jobIds:  [jobId],
        };

        updateRequisitionIds();
        refreshBranchButtons();

        var tag = document.createElement('span');
        tag.setAttribute('data-job-id', key);
        tag.style.cssText = 'display:inline-flex; align-items:center; gap:6px; background:#fff5f5; color:#FA0000; border:1px solid #FA0000; border-radius:999px; padding:4px 12px; font-size:13px; font-weight:600; font-family:"Aloevera",system-ui,sans-serif;';
        tag.innerHTML = branch + ' ✕';
        tag.querySelector('button').addEventListener('click', function() {
            delete selectedBranches[key];
            tag.remove();
            updateRequisitionIds();
            refreshBranchButtons();
        });
        branchTags.appendChild(tag);

        kualeCloseModal(branchOverlay);
    });
});

document.addEventListener('DOMContentLoaded', function () {
    // Otra red social
    var otherPlatform = document.getElementById('other_network_profile_platform');
    var otherHidden   = document.getElementById('other_network_profile');

    if (otherPlatform && otherHidden) {
        otherPlatform.addEventListener('input', function () {
            var val = otherPlatform.value.trim();
            if (val) {
                val = val.replace(/^https?:\/\/(www\.)?/, '');
                if (val.indexOf(' ') !== -1) {
                    var parts    = val.split(/\s+/);
                    var platform = parts[0].replace(/\.com.*$/, '');
                    var username = parts.slice(1).join('');
                    val = platform + '.com/' + username;
                }
                otherHidden.value = 'https://www.' + val;
            } else {
                otherHidden.value = '';
            }
        });
    }

    // Facebook 
    var fbUsername = document.getElementById('facebook_username');
    var fbHidden   = document.getElementById('facebook_profile');

    if (fbUsername && fbHidden) {
        fbUsername.addEventListener('input', function () {
            var val = fbUsername.value.trim();
            if (val) {
                // Si pegó URL completa, extraer solo el username
                val = val.replace(/^https?:\/\/(www\.)?facebook\.com\//, '');
                // Quitar slash final
                val = val.replace(/\/$/, '');
                // Si tiene espacios, convertir a formato facebook: minúsculas sin espacios con puntos
                if (val.indexOf(' ') !== -1) {
                    val = val.toLowerCase().replace(/\s+/g, '.');
                }
                fbHidden.value = 'https://www.facebook.com/' + val + '/';
            } else {
                fbHidden.value = '';
            }
        });
    }
});

(function() {
    var alertModal = document.getElementById('alertModal');
    if (!alertModal) {
        document.addEventListener('DOMContentLoaded', function() {
            alertModal = document.getElementById('alertModal');
            if (alertModal) bindAlertModal(alertModal);
        });
    } else {
        bindAlertModal(alertModal);
    }

    function bindAlertModal(el) {
        el.addEventListener('show.bs.modal', function() {
            document.body.classList.add('kuale-modal-open');
        });
        el.addEventListener('hidden.bs.modal', function() {
            document.body.classList.remove('kuale-modal-open');
        });
    }
})();

